  {
    id: 'form_registration_official',
    shareToken: 'signup',
    title: '现场人员报名登记表',
    description: '请填写基本信息及银行卡资料，以便工资发放。',
    status: 'ACTIVE',
    createdDate: new Date().toISOString().split('T')[0],
    submissionCount: 3,
    themeColor: 'blue',
    fields: [
       { id: 'f_name', type: 'TEXT', label: '姓名', required: true, placeholder: '请输入真实姓名' },
       { id: 'f_gender', type: 'GENDER', label: '性别', required: true, options: ['男', '女'] },
       { id: 'f_idcard', type: 'ID_CARD', label: '身份证号码', required: true, placeholder: '用于购买保险及核验' },
       { id: 'f_dob', type: 'DATE', label: '出生日期', required: true },
       { id: 'f_phone', type: 'PHONE', label: '手机号码', required: true, placeholder: '用于接收通知' },
       { id: 'f_email', type: 'EMAIL', label: '电子邮箱', required: false, placeholder: '选填' },
       { id: 'f_bank_name', type: 'SELECT', label: '开户银行', required: true, options: ['工商银行', '建设银行', '农业银行', '中国银行', '招商银行', '其他银行'] },
       { id: 'f_bank_branch', type: 'TEXT', label: '支行信息', required: true, placeholder: '例如：广州天河支行' },
       { id: 'f_bank_no', type: 'BANK_CARD', label: '银行卡号', required: true, placeholder: '请输入卡号' },
       { id: 'f_bank_note', type: 'TEXT', label: '银行卡备注', required: false, placeholder: '非本人卡请注明持卡人姓名及关系' },
       { id: 'f_schedule', type: 'SCHEDULE', label: '可参与工作时间', required: true, config: { dates: ['5.1', '5.2', '5.3', '5.4', '5.5'] } }
    ]
  },
];

const generateMockAttendance = (staffList: Staff[]): AttendanceRecord[] => {
  const records: AttendanceRecord[] = [];
  const today = new Date();

  staffList.filter(s => s.status === 'ACTIVE').forEach(staff => {
    for (let i = 1; i < 7; i++) {
      const date = new Date(today);
      date.setDate(today.getDate() - i);
      if (date.getDay() !== 0 && date.getDay() !== 6 && Math.random() > 0.1) {
        records.push({
           id: crypto.randomUUID(),
           staffId: staff.id,
           timestamp: new Date(date.setHours(8, 55 + Math.floor(Math.random()*15))).toISOString(),
           type: 'IN',
           status: Math.random() > 0.9 ? 'LATE' : 'NORMAL',
           photoUrl: `https://api.dicebear.com/7.x/avataaars/svg?seed=${staff.id}_${i}`
        });
      }
    }
  });
  return records;
};

const App: React.FC = () => {
  const [session, setSession] = useState<UserSession | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  const [staffList, setStaffList] = useState<Staff[]>([]);
  const [queueData, setQueueData] = useState<QueueTicket[]>([]);
  const [announcements, setAnnouncements] = useState<Announcement[]>([]);
  const [registrationList, setRegistrationList] = useState<RegistrationRecord[]>([]);
  const [onSiteRecords, setOnSiteRecords] = useState<RegistrationRecord[]>([]);
  const [attendanceRecords, setAttendanceRecords] = useState<AttendanceRecord[]>([]);
  const [groups, setGroups] = useState<Group[]>([]);
  const [forms, setForms] = useState<FormTemplate[]>([]);
  const [formSubmissions, setFormSubmissions] = useState<FormSubmission[]>([]);
  const [adminUsers, setAdminUsers] = useState<AdminUser[]>([]);

  const [selectedFormId, setSelectedFormId] = useState<string | null>(null); 
  const [designerMode, setDesignerMode] = useState<'NONE' | 'EDIT' | 'ANALYTICS' | 'PREVIEW'>('NONE');
  const [systemDomain, setSystemDomain] = useState('https://workpulse.app');

  const [attendanceConfig, setAttendanceConfig] = useState<AttendanceConfig>({ startTime: '09:00', endTime: '18:00', overtimeStart: '19:00' });
  const [permissionSettings, setPermissionSettings] = useState<PermissionSettings>({
      allowLeaderExport: true,
      allowLeaderBroadcast: true,
      allowStaffViewTeam: false,
      showSensitiveInfo: true, 
      enableCheckIn: true,
  });
  const [loginConfig, setLoginConfig] = useState<LoginConfig>({ title: 'STAFFTool', subtitle: '', imageUrl: '', logoUrl: '' });
  const [registrationConfig, setRegistrationConfig] = useState<RegistrationConfig>({ masterPrefix: 'M', onSitePrefix: 'S' });

  // Initial Data Load (Simulating API fetch)
  useEffect(() => {
    const refreshData = async () => {
      setIsLoading(true);
      await new Promise(resolve => setTimeout(resolve, 800)); // Slightly longer delay to show spinner

      const load = (key: string, def: any) => {
         const saved = localStorage.getItem(key);
         return saved ? JSON.parse(saved) : def;
      };

      setStaffList(load('staffList', []));
      setQueueData(load('queueData', []));
      setAnnouncements(load('announcements', MOCK_ANNOUNCEMENTS));
      setRegistrationList(load('registrationList', []));
      setOnSiteRecords(load('onSiteRecords', []));

      const savedAttendance = load('attendanceRecords', []);
      if (savedAttendance.length === 0) {
         setAttendanceRecords(generateMockAttendance(load('staffList', [])));
      } else {
         setAttendanceRecords(savedAttendance);
      }

      setGroups(load('groups', MOCK_GROUPS));
      setForms(load('forms', MOCK_FORMS));
      setFormSubmissions(load('formSubmissions', []));
      setAdminUsers(load('adminUsers', [{ username: 'admin', password: 'password' }]));
      setSystemDomain(localStorage.getItem('systemDomain') || 'https://workpulse.app');
      setAttendanceConfig(load('attendanceConfig', { startTime: '09:00', endTime: '18:00', overtimeStart: '19:00' }));
      setPermissionSettings(load('permissionSettings', { allowLeaderExport: true, allowLeaderBroadcast: true, allowStaffViewTeam: false, showSensitiveInfo: true, enableCheckIn: true }));
      setLoginConfig(load('loginConfig', { title: 'STAFFTool', subtitle: '', imageUrl: '', logoUrl: '' }));
      setRegistrationConfig(load('registrationConfig', { masterPrefix: 'M', onSitePrefix: 'S' }));

      setIsLoading(false);
    };

    refreshData();
  }, []);

  // --- Real-time Synchronization (Simulating Socket/Backend) ---
  useEffect(() => {
    // Only run if not loading
    if (isLoading) return;

    const syncStateFromStorage = () => {
      const syncItem = (key: string, setter: React.Dispatch<React.SetStateAction<any>>) => {
        const saved = localStorage.getItem(key);
        if (saved) {
          try {
            const parsed = JSON.parse(saved);
            setter((prev: any) => {
              if (JSON.stringify(prev) !== saved) {
                return parsed;
              }
              return prev;
            });
          } catch(e) { console.error('Sync parse error', e); }
        }
      };

      syncItem('queueData', setQueueData);
      syncItem('attendanceRecords', setAttendanceRecords);
      syncItem('registrationList', setRegistrationList);
      syncItem('onSiteRecords', setOnSiteRecords);
      syncItem('staffList', setStaffList);
    };

    window.addEventListener('storage', syncStateFromStorage);
    const intervalId = setInterval(syncStateFromStorage, 1500);

    return () => {
      window.removeEventListener('storage', syncStateFromStorage);
      clearInterval(intervalId);
    };
  }, [isLoading]);

  // --- Start of CRUD / State Persistence (Sync back to localStorage) ---
  useEffect(() => { if(!isLoading) localStorage.setItem('staffList', JSON.stringify(staffList)); }, [staffList, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('queueData', JSON.stringify(queueData)); }, [queueData, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('announcements', JSON.stringify(announcements)); }, [announcements, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('registrationList', JSON.stringify(registrationList)); }, [registrationList, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('onSiteRecords', JSON.stringify(onSiteRecords)); }, [onSiteRecords, isLoading]); 
  useEffect(() => { if(!isLoading) localStorage.setItem('attendanceRecords', JSON.stringify(attendanceRecords)); }, [attendanceRecords, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('groups', JSON.stringify(groups)); }, [groups, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('forms', JSON.stringify(forms)); }, [forms, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('formSubmissions', JSON.stringify(formSubmissions)); }, [formSubmissions, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('systemDomain', systemDomain); }, [systemDomain, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('attendanceConfig', JSON.stringify(attendanceConfig)); }, [attendanceConfig, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('permissionSettings', JSON.stringify(permissionSettings)); }, [permissionSettings, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('adminUsers', JSON.stringify(adminUsers)); }, [adminUsers, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('loginConfig', JSON.stringify(loginConfig)); }, [loginConfig, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('registrationConfig', JSON.stringify(registrationConfig)); }, [registrationConfig, isLoading]);
  // --- End of State Persistence ---

  const handleLogin = (userId: string, role: 'ADMIN' | 'USER') => {
    if (role === 'ADMIN') {
      setSession({ userId, role });
      setActiveTab('dashboard');
    } else {
      let staff = staffList.find(s => s.id === userId);

      if (!staff) {
        const candidate = registrationList.find(r => r.id === userId) || onSiteRecords.find(r => r.id === userId);
        if (candidate) {
          staff = {
            id: candidate.id,
            name: candidate.name,
            idCard: candidate.idCard || '',
            phone: candidate.phone,
            status: 'PENDING', 
            roles: [],
            avatar: '',
            joinDate: candidate.submissionTime,
            registrationNumber: candidate.registrationNumber
          };
        }
      }

      if (staff) {
        setSession({ userId, role, staff });
        const isPendingAllocation = staff.roles.some(r => r.groupId === 'g_pending_allocation');
        const hasNoGroup = staff.roles.length === 0;
        const isNotActive = staff.status === 'PENDING' || staff.status === 'INTERVIEWED';

        if (isNotActive || isPendingAllocation || hasNoGroup) {
          setActiveTab('interviewee_dashboard');
        } else {
          setActiveTab('dashboard');
        }
      }
    };
  };

  const handleLogout = () => {
    setSession(null);
    setActiveTab('dashboard');
  };

  const handleStaffClockIn = (photoUrl: string, status: AttendanceRecord['status'], timestamp: string) => {
    if (!session?.staff) return;
    const newRecord: AttendanceRecord = {
      id: crypto.randomUUID(),
      staffId: session.staff.id,
      timestamp: timestamp, 
      type: 'IN',
      photoUrl,
      status
    };
    setAttendanceRecords([newRecord, ...attendanceRecords]);
  };

  const handleStaffClockOut = (photoUrl: string, status: AttendanceRecord['status'], timestamp: string) => {
    if (!session?.staff) return;
    const newRecord: AttendanceRecord = {
      id: crypto.randomUUID(),
      staffId: session.staff.id,
      timestamp: timestamp, 
      type: 'OUT',
      photoUrl,
      status
    };
    setAttendanceRecords([newRecord, ...attendanceRecords]);
  };

  const handleUpdateOrAddRecord = (staffId: string, dateStr: string, type: 'IN' | 'OUT', timeStr: string) => {
    if (!timeStr) return;
    const targetTimestamp = new Date(`${dateStr}T${timeStr}`);
    const calculateStatus = (recType: 'IN' | 'OUT', checkTime: Date): AttendanceRecord['status'] => {
      const time = checkTime.toLocaleTimeString('en-GB', { hour12: false, hour: '2-digit', minute: '2-digit' });
      if (recType === 'IN') {
        return time > attendanceConfig.startTime ? 'LATE' : 'NORMAL';
      } else {
        if (time < attendanceConfig.endTime) return 'EARLY_LEAVE';
        if (time > attendanceConfig.overtimeStart) return 'OVERTIME';
        return 'NORMAL';
      }
    };
    const newStatus = calculateStatus(type, targetTimestamp);
    const isSameDay = (d1: string | Date, d2: string | Date) => {
      const date1 = new Date(d1);
      const date2 = new Date(d2);
      return date1.getFullYear() === date2.getFullYear() &&
             date1.getMonth() === date2.getMonth() &&
             date1.getDate() === date2.getDate();
    };
    let recordExists = false;
    const updatedRecords = attendanceRecords.map(rec => {
      if (rec.staffId === staffId && isSameDay(rec.timestamp, dateStr) && rec.type === type) {
        recordExists = true;
        return {
          ...rec,
          timestamp: targetTimestamp.toISOString(),
          status: newStatus,
          isManual: true,
          photoUrl: rec.photoUrl 
        };
      }
      return rec;
    });
    if (recordExists) {
      setAttendanceRecords(updatedRecords);
    } else {
      const newRecord: AttendanceRecord = {
        id: crypto.randomUUID(),
        staffId,
        timestamp: targetTimestamp.toISOString(),
        type,
        status: newStatus,
        isManual: true
      };
      setAttendanceRecords(prev => [newRecord, ...prev]);
    }
  };

  const handleQueueCheckIn = (staffId: string) => {
    if (queueData.some(t => t.staffId === staffId)) return;
    let person: Staff | RegistrationRecord | undefined = staffList.find(s => s.id === staffId);
    if (!person) person = registrationList.find(r => r.id === staffId);
    if (!person) person = onSiteRecords.find(r => r.id === staffId);
    if (!person) return; 
    const newTicket: QueueTicket = {
      id: crypto.randomUUID(),
      ticketNumber: `A-${String(queueData.length + 1).padStart(3, '0')}`,
      staffId: person.id,
      staffName: person.name,
      status: 'WAITING',
      checkInTime: new Date().toISOString()
    };
    setQueueData(prev => [...prev, newTicket]);

    // Auto generate an attendance record for check-in
    const photoUrl = 'avatar' in person ? person.avatar : `https://api.dicebear.com/7.x/avataaars/svg?seed=${person.id}`;
    const now = new Date();
    const currentTimeStr = now.toLocaleTimeString('en-GB', { hour12: false, hour: '2-digit', minute: '2-digit' });
    let status: AttendanceRecord['status'] = 'NORMAL';
    if (currentTimeStr > attendanceConfig.startTime) status = 'LATE';
    const newRecord: AttendanceRecord = {
      id: crypto.randomUUID(),
      staffId: person.id,
      timestamp: now.toISOString(),
      type: 'IN',
      photoUrl: photoUrl,
      status: status
    };
    setAttendanceRecords(prev => [...prev, newRecord]);
  };

  const updateTicketStatus = (ticketId: string, status: QueueTicket['status']) => {
    setQueueData(queueData.map(t => t.id === ticketId ? { ...t, status } : t));
  };

  const handleBatchAddStaffFromReg = (newStaffList: Staff[]) => {
    let count = 0;
    const updatedStaffList = [...staffList];
    newStaffList.forEach(newStaff => {
       const exists = updatedStaffList.some(s => 
          (s.idCard && s.idCard === newStaff.idCard) || 
          (s.phone && s.phone === newStaff.phone && s.name === newStaff.name)
       );
       if (!exists) {
         updatedStaffList.push(newStaff);
         count++;
       }
    });
    setStaffList(updatedStaffList);
    alert(`已成功将 ${count} 名新人员导入为正式员工/候选人，可直接登录系统。`);
  };

  const handleAddGroup = (group: Group) => setGroups([...groups, group]);
  const handleUpdateGroup = (group: Group) => setGroups(groups.map(g => g.id === group.id ? group : g));
  const handleDeleteGroup = (groupId: string) => setGroups(groups.filter(g => g.id !== groupId));
  const handleUpdateStaff = (staff: Staff) => setStaffList(staffList.map(s => s.id === staff.id ? staff : s));
  const handleAddStaff = (staff: Staff) => setStaffList([...staffList, staff]);
  const handleAddAdmin = (user: AdminUser): boolean => {
    if (adminUsers.some(u => u.username === user.username)) {
      alert('用户名已存在！');
      return false;
    }
    setAdminUsers([...adminUsers, user]);
    return true;
  };
  const handleDeleteAdmin = (username: string) => {
    if (adminUsers.length <= 1) {
       alert('不能删除唯一的管理员账户！');
       return;
    }
    if (confirm(`确定要删除管理员 "${username}" 吗？`)) {
      setAdminUsers(adminUsers.filter(u => u.username !== username));
    }
  };
  const handleUpdateAdminPassword = (username: string, newPass: string) => {
    setAdminUsers(adminUsers.map(u => u.username === username ? { ...u, password: newPass } : u));
    alert(`管理员 ${username} 的密码已修改`);
  };

  const handleCreateForm = () => {
    const newForm: FormTemplate = {
      id: crypto.randomUUID(),
      shareToken: crypto.randomUUID().slice(0, 8),
      title: '未命名人员登记表',
      description: '请填写基本信息及银行卡资料，以便工资发放。',
      status: 'ACTIVE', 
      createdDate: new Date().toISOString().split('T')[0],
      submissionCount: 0,
      themeColor: 'blue',
      fields: [
        { id: crypto.randomUUID(), type: 'TEXT', label: '姓名', required: true, placeholder: '请输入真实姓名' },
        { id: crypto.randomUUID(), type: 'PHONE', label: '手机号码', required: true, placeholder: '11位手机号' },
      ]
    };
    setForms([...forms, newForm]);
    setSelectedFormId(newForm.id);
    setDesignerMode('EDIT');
    setActiveTab('form_designer');
  };
  const handleToggleFormStatus = (formId: string, newStatus: 'ACTIVE' | 'CLOSED') => {
    setForms(forms.map(f => f.id === formId ? { ...f, status: newStatus } : f));
  };
  const handleDeleteForm = (id: string) => {
    if (confirm('确定要删除此表单吗？所有收集的数据也将被删除。')) {
      setForms(forms.filter(f => f.id !== id));
      setFormSubmissions(formSubmissions.filter(s => s.formId !== id));
    }
  };
  const handleDeleteSubmission = (submissionId: string) => {
    if (confirm('确定要删除这条提交记录吗？')) {
      setFormSubmissions(prev => prev.filter(s => s.id !== submissionId));
    }
  };
  const handleSaveForm = (updatedForm: FormTemplate) => {
    setForms(forms.map(f => f.id === updatedForm.id ? updatedForm : f));
  };
  const handleFormSubmit = (submission: FormSubmission) => {
    setFormSubmissions([...formSubmissions, submission]);
    setForms(forms.map(f => f.id === submission.formId ? { ...f, submissionCount: f.submissionCount + 1 } : f));
  };
  const handleSaveSettings = (settings: { domain: string, attendance: AttendanceConfig, permissions: PermissionSettings, loginConfig: LoginConfig, registrationConfig: RegistrationConfig }) => {
    setSystemDomain(settings.domain);
    setAttendanceConfig(settings.attendance);
    setPermissionSettings(settings.permissions);
    setLoginConfig(settings.loginConfig);
    setRegistrationConfig(settings.registrationConfig);
  };
  const handleNavigateToForm = (formId: string, mode: 'EDIT' | 'ANALYTICS' | 'PREVIEW') => {
    setSelectedFormId(formId);
    setDesignerMode(mode);
    setActiveTab('form_designer');
  };

  const renderContent = () => {
    // 1. GLOBAL LOADING SPINNER
    if (isLoading) return (
        <div className="flex h-full items-center justify-center">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600"></div>
        </div>
    );

    if (activeTab === 'interviewee_dashboard' && session?.staff) {
      const myTicket = queueData.find(t => t.staffId === session.staff?.id);
      const ticketsAhead = queueData.filter(t => 
        t.status === 'WAITING' && 
        myTicket && 
        new Date(t.checkInTime) < new Date(myTicket.checkInTime)
      ).length;

      return (
        <IntervieweeDashboard 
          staff={session.staff} 
          myTicket={myTicket}
          ticketsAhead={ticketsAhead}
          onLogout={handleLogout}
        />
      );
    }

    if (activeTab === 'form_designer' && selectedFormId) {
       const form = forms.find(f => f.id === selectedFormId);
       if (!form) return <div>Form not found</div>;
       if (designerMode === 'EDIT') return <FormDesigner form={form} onSave={handleSaveForm} onPublish={() => setDesignerMode('PREVIEW')} onBack={() => setActiveTab('form_manager')} />;
       if (designerMode === 'ANALYTICS') return <FormAnalytics form={form} submissions={formSubmissions.filter(s => s.formId === form.id)} onDeleteSubmission={handleDeleteSubmission} onBack={() => setActiveTab('form_manager')} onShare={() => setDesignerMode('PREVIEW')} />;
       if (designerMode === 'PREVIEW') return <FormShareDashboard form={form} onBack={() => setDesignerMode('ANALYTICS')} onPreview={() => setActiveTab('public_view_simulation')} customDomain={systemDomain} />; 
    }

    switch (activeTab) {
      case 'dashboard':
        if (session?.role === 'USER' && session?.staff) {
          const userGroup = groups.find(g => session.staff?.roles.some(r => r.groupId === g.id));
          const groupLeaders = staffList.filter(s => s.roles.some(r => r.groupId === userGroup?.id && r.isLeader));
          const myAnnouncements = announcements.filter(a => !a.targetGroupId || a.targetGroupId === userGroup?.id);
          const myRecords = attendanceRecords.filter(r => r.staffId === session.staff?.id).sort((a,b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
          const lastRecord = myRecords[0];
          const status = lastRecord?.type === 'IN' ? AttendanceStatus.CLOCKED_IN : AttendanceStatus.CLOCKED_OUT;

          return (
            <StaffDashboard 
              currentUser={session.staff}
              group={userGroup}
              leaders={groupLeaders} 
              staffList={staffList}
              announcements={myAnnouncements}
              attendanceStatus={status}
              attendanceHistory={myRecords.filter(r => new Date(r.timestamp).toDateString() === new Date().toDateString())}
              attendanceConfig={attendanceConfig}
              onClockIn={handleStaffClockIn}
              onClockOut={handleStaffClockOut}
            />
          );
        }
        return <Dashboard 
          attendanceRecords={attendanceRecords}
          queueData={queueData}
          announcements={announcements}
          isAdmin={session?.role === 'ADMIN'}
          groupInfo={session?.staff?.roles[0]}
          staffList={staffList}
          groups={groups}
          currentUser={session?.staff}
        />;

      case 'reports':
        let visibleGroups = groups;
        if (session?.role === 'USER' && session.staff) {
           const leaderGroupIds = session.staff.roles.filter(r => r.isLeader).map(r => r.groupId);
           visibleGroups = groups.filter(g => leaderGroupIds.includes(g.id));
        }
        return <AttendanceReports 
          staffList={staffList} 
          groups={visibleGroups} 
          allRecords={attendanceRecords}
          session={session}
          permissionSettings={permissionSettings}
          attendanceConfig={attendanceConfig}
          onUpdateOrAddRecord={handleUpdateOrAddRecord}
          fixedGroupId={visibleGroups.length === 1 ? visibleGroups[0].id : undefined} 
        />;

      case 'checkin_system':
        return <CheckInSystem 
          queue={queueData}
          registrationList={registrationList}
          onSiteRecords={onSiteRecords}
          staffList={staffList}
          onCheckIn={handleQueueCheckIn}
          onClearQueue={() => setQueueData([])}
