                 {activeTab === 'CANDIDATE' && '面试签到'}
                 {activeTab === 'EMPLOYEE' && '员工登录'}
                 {activeTab === 'ADMIN' && '管理后台'}
              </h2>
           </div>
        </div>

        <div className="flex-1 flex flex-col items-center justify-center p-6 md:p-12 overflow-y-auto">
