                            value={formData.idCardSuffix}
                            onChange={e => setFormData({...formData, idCardSuffix: e.target.value})}
                            className="w-full pl-11 pr-4 py-4 bg-gray-50 border border-transparent rounded-2xl focus:bg-white focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all text-sm font-medium placeholder-gray-400"
                          />
