import React, { useMemo } from 'react';
import { 
  Users, 
  Clock, 
  Megaphone, 
  CheckCircle2, 
  CalendarDays, 
  Sun, 
  Moon, 
  ArrowRight,
  TrendingUp,
  Activity,
  Shield,
  BarChart3
} from 'lucide-react';
import { AttendanceRecord, QueueTicket, Announcement, Staff, Group, GroupRole } from '../types';

interface DashboardProps {
  attendanceRecords: AttendanceRecord[];
  queueData: QueueTicket[];
  announcements: Announcement[];
  isAdmin: boolean;
  groupInfo?: GroupRole;
  staffList: Staff[];
  groups: Group[];
  currentUser?: Staff;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  attendanceRecords, 
  queueData,
  announcements, 
  isAdmin, 
  staffList, 
  groups,
  currentUser
}) => {

  // 1. Calculate Personal Stats (Only for Non-Admin)
  const myRecords = useMemo(() => {
    if (isAdmin || !currentUser) return [];
    return attendanceRecords
      .filter(r => r.staffId === currentUser.id)
      .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime())
      .slice(0, 10);
  }, [attendanceRecords, currentUser, isAdmin]);

  const lastClockIn = useMemo(() => {
    return myRecords.find(r => r.type === 'IN');
  }, [myRecords]);

  // 2. Global Stats for Admin
  const todayStr = new Date().toDateString();
  const globalStats = useMemo(() => {
     const todayRecords = attendanceRecords.filter(r => new Date(r.timestamp).toDateString() === todayStr && r.type === 'IN');
     // Deduplicate by staffId
     const presentStaffIds = new Set(todayRecords.map(r => r.staffId));
     const activeStaffCount = staffList.filter(s => s.status === 'ACTIVE').length;
     const presentCount = presentStaffIds.size;

     return {
        present: presentCount,
        total: activeStaffCount,
        rate: activeStaffCount > 0 ? Math.round((presentCount / activeStaffCount) * 100) : 0,
        missing: Math.max(0, activeStaffCount - presentCount)
     };
  }, [attendanceRecords, staffList, todayStr]);

  // 3. Calculate Group Stats (Present vs Absent for TODAY)
  const groupStats = useMemo(() => {
    return groups.map(group => {
      const groupStaff = staffList.filter(s => s.status === 'ACTIVE' && s.roles.some(r => r.groupId === group.id));
      const total = groupStaff.length;

      const presentCount = groupStaff.filter(s => {
         return attendanceRecords.some(r => 
            r.staffId === s.id && 
            r.type === 'IN' && 
            new Date(r.timestamp).toDateString() === todayStr
         );
      }).length;

      return {
        id: group.id,
        name: group.name,
        total,
        present: presentCount,
        rate: total > 0 ? Math.round((presentCount / total) * 100) : 0
      };
    });
  }, [groups, staffList, attendanceRecords, todayStr]);

  const sortedAnnouncements = useMemo(() => {
    return [...announcements].sort((a, b) => {
      if (a.isSticky && !b.isSticky) return -1;
      if (!a.isSticky && b.isSticky) return 1;
      return new Date(b.date).getTime() - new Date(a.date).getTime();
    });
  }, [announcements]);

  const getCurrentGreeting = () => {
    const hour = new Date().getHours();
    if (hour < 12) return 'Good Morning,';
    if (hour < 18) return 'Good Afternoon,';
    return 'Good Evening,';
  };

  return (
    <div className="space-y-6 animate-fade-in max-w-7xl mx-auto">

      {/* Header & Personal Status */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {/* Welcome Section */}
        <div className="md:col-span-2 bg-gradient-to-br from-indigo-600 via-violet-600 to-purple-600 rounded-[2.5rem] p-8 text-white shadow-xl shadow-indigo-500/30 relative overflow-hidden group min-h-[220px] flex flex-col justify-center">
           {/* Decorative Background */}
           <div className="absolute top-0 right-0 w-80 h-80 bg-white/10 rounded-full blur-3xl -mr-20 -mt-20 group-hover:scale-110 transition-transform duration-1000 ease-in-out"></div>
           <div className="absolute bottom-0 left-0 w-64 h-64 bg-indigo-400/20 rounded-full blur-3xl -ml-16 -mb-16"></div>

           <div className="relative z-10">
              <div className="flex items-center gap-2 mb-2">
                 <span className="bg-white/20 backdrop-blur-md px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider border border-white/10 flex items-center gap-1.5">
                    <CalendarDays size={12} />
                    {new Date().toLocaleDateString('zh-CN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
                 </span>
                 {isAdmin && (
                    <span className="bg-orange-500/20 backdrop-blur-md px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider border border-orange-400/30 text-orange-100 flex items-center gap-1.5">
                        <Shield size={12} /> 管理员模式
                    </span>
                 )}
              </div>
              <h1 className="text-4xl md:text-5xl font-black tracking-tight mb-2 opacity-95">
                 {getCurrentGreeting()}
                 <br/>
                 <span className="text-transparent bg-clip-text bg-gradient-to-r from-white to-indigo-200">
                    {isAdmin ? 'Administrator' : currentUser?.name}
                 </span>
              </h1>
              <p className="text-indigo-100 text-sm font-medium mt-2 max-w-md opacity-80">
                 {isAdmin ? '今日系统运行正常，各项考勤数据实时同步中。' : '让我们开始高效的一天吧！查看下方的今日概览。'}
              </p>
           </div>
        </div>

        {/* Action / Status Card */}
        {isAdmin ? (
            // --- ADMIN VIEW: System Pulse ---
            <div className="bg-white rounded-[2.5rem] p-8 shadow-sm border border-gray-100 flex flex-col justify-between hover:shadow-lg transition-all duration-300 relative overflow-hidden group">
                <div className="absolute top-0 right-0 p-6 opacity-5 group-hover:opacity-10 transition-opacity">
                    <BarChart3 size={100} />
                </div>
                <div>
                    <p className="text-gray-400 text-xs font-extrabold uppercase tracking-widest mb-4 flex items-center gap-1">
                        <Activity size={12} /> 今日考勤概览
                    </p>
                    <div className="flex items-center gap-4">
                        <div className="w-16 h-16 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center shadow-inner">
                            <Users size={28} strokeWidth={3} />
                        </div>
                        <div>
                            <h3 className="font-black text-gray-800 text-3xl tracking-tight leading-none">
                                {globalStats.present} <span className="text-base text-gray-400 font-medium">/ {globalStats.total}</span>
                            </h3>
                            <p className="text-xs text-gray-500 font-bold mt-1">实到人数 / 总人数</p>
                        </div>
                    </div>
                </div>

                <div className="mt-6">
                    <div className="w-full bg-gray-100 h-2 rounded-full overflow-hidden mb-2">
                        <div className={`h-full rounded-full transition-all duration-1000 ${globalStats.rate >= 90 ? 'bg-green-500' : 'bg-indigo-500'}`} style={{width: `${globalStats.rate}%`}}></div>
                    </div>
                    <div className="flex justify-between text-xs font-bold text-gray-400">
                        <span>出勤率 {globalStats.rate}%</span>
                        <span className="text-orange-400">缺勤 {globalStats.missing} 人</span>
                    </div>
                </div>
            </div>
        ) : (
            // --- USER VIEW: Personal Status ---
            <div className="bg-white rounded-[2.5rem] p-8 shadow-sm border border-gray-100 flex flex-col justify-between hover:shadow-lg transition-all duration-300 relative overflow-hidden group">
                <div className="absolute top-0 right-0 p-6 opacity-5 group-hover:opacity-10 transition-opacity">
                    <Clock size={100} />
                </div>
                <div>
                    <p className="text-gray-400 text-xs font-extrabold uppercase tracking-widest mb-4 flex items-center gap-1">
                        <Activity size={12} /> 我的状态
                    </p>
                    <div className="flex items-center gap-4">
                        <div className={`w-16 h-16 rounded-2xl flex items-center justify-center shadow-lg transform group-hover:scale-105 transition-transform duration-300 ${lastClockIn ? 'bg-green-500 text-white shadow-green-200' : 'bg-gray-100 text-gray-400'}`}>
                            <Clock size={28} strokeWidth={3} />
                        </div>
                        <div>
                            <h3 className="font-black text-gray-800 text-3xl tracking-tight leading-none">
                            {lastClockIn ? new Date(lastClockIn.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : '--:--'}
                            </h3>
                            <p className="text-xs text-gray-500 font-bold mt-1">最近打卡</p>
                        </div>
                    </div>
                </div>

                <div className="mt-6">
                    {lastClockIn ? (
                        <div className="bg-green-50 text-green-700 px-4 py-2.5 rounded-xl font-bold text-xs flex items-center justify-between border border-green-100">
                            <span className="flex items-center gap-1.5"><CheckCircle2 size={14} /> 状态正常</span>
                            <span className="opacity-70">Working</span>
                        </div>
                    ) : (
                        <div className="bg-gray-50 text-gray-500 px-4 py-2.5 rounded-xl font-bold text-xs flex items-center justify-between border border-gray-100">
                            <span className="flex items-center gap-1.5"><Moon size={14} /> 未打卡</span>
                            <span className="opacity-70">Idle</span>
                        </div>
                    )}
                </div>
            </div>
        )}
      </div>

      {/* Announcements Scroller */}
      {sortedAnnouncements.length > 0 && (
         <div className="bg-white rounded-3xl p-1 shadow-sm border border-gray-100 flex items-center">
            <div className="bg-orange-100 text-orange-600 p-2.5 rounded-2xl m-1 shrink-0">
               <Megaphone size={20} />
            </div>
            <div className="flex-1 px-3 overflow-hidden">
               <div className="animate-marquee whitespace-nowrap flex items-center gap-8">
                  {sortedAnnouncements.map(ann => (
                     <span key={ann.id} className="text-sm font-bold text-gray-700 flex items-center gap-2">
                        <span className="w-1.5 h-1.5 rounded-full bg-orange-400"></span>
