            <span className="text-xs font-bold text-gray-400 bg-white border border-gray-200 px-3 py-1.5 rounded-full flex items-center gap-1">
               <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div> 实时数据
            </span>
         </div>

         <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-5">
            {groupStats.length === 0 ? (
               <div className="col-span-full p-12 bg-white rounded-[2rem] text-center text-gray-400 border-2 border-dashed border-gray-200">
                  <p>暂无分组数据</p>
               </div>
            ) : (
               groupStats.map((group, idx) => (
                  <div key={group.id} className="bg-white p-6 rounded-[2rem] shadow-sm border border-gray-100 hover:shadow-xl hover:shadow-indigo-500/10 hover:-translate-y-1 transition-all duration-300 group flex flex-col justify-between min-h-[140px]">

                     <div className="flex justify-between items-start mb-4">
                        <h3 className="font-bold text-gray-800 text-lg truncate pr-2 w-full" title={group.name}>{group.name}</h3>
                        <div className={`flex items-center gap-1 text-xs font-bold px-2 py-1 rounded-lg shrink-0 ${
                           group.rate >= 90 ? 'bg-green-50 text-green-600' : 
