  // New control props
  allowFormSync?: boolean;
  allowExcelImport?: boolean;
  allowManualEntry?: boolean;
  idPrefix?: string; // New: Custom ID Prefix
}

// ... (Existing AVAILABILITY_STATES and STATE_CONFIG kept same)
