import React, { useState, useRef, useEffect, useCallback } from 'react';
import { AlertCircle, Clock, CheckCircle2 } from 'lucide-react';
import { AttendanceRecord, AttendanceStatus, AttendanceConfig } from '../types';
import { calculateAttendanceStatus } from '../utils';

interface AttendanceProps {
  onClockIn: (photoUrl: string, status: AttendanceRecord['status'], timestamp: string) => void;
  onClockOut: (photoUrl: string, status: AttendanceRecord['status'], timestamp: string) => void;
  status: AttendanceStatus;
  config: AttendanceConfig;
}

const Attendance: React.FC<AttendanceProps> = ({ onClockIn, onClockOut, status, config }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [error, setError] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [currentTime, setCurrentTime] = useState(new Date());

  // Update clock every second for display
  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({ 
          video: { 
              facingMode: { ideal: 'user' },
              width: { ideal: 1280 }, // Optimize resolution for backend
              height: { ideal: 720 }
          } 
      });
      setStream(mediaStream);
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
      }
      setError('');
    } catch (err) {
      console.error("Error accessing camera:", err);
      setError('无法访问摄像头，请检查权限。');
    }
  };

  const stopCamera = useCallback(() => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
  }, [stream]);

  useEffect(() => {
    startCamera();
    return () => {
      stopCamera();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); 

  useEffect(() => {
    if (videoRef.current && stream && !videoRef.current.srcObject) {
      videoRef.current.srcObject = stream;
    }
  }, [stream, status]);

  // Capture Photo - Returns both DataURL (for preview) and Blob (for upload)
  const capturePhotoData = (): Promise<{ dataUrl: string; blob: Blob } | null> => {
    return new Promise((resolve) => {
      if (!videoRef.current || !canvasRef.current) {
        resolve(null);
        return;
      }
      const context = canvasRef.current.getContext('2d');
      if (!context) {
        resolve(null);
        return;
      }

      const width = videoRef.current.videoWidth;
      const height = videoRef.current.videoHeight;

      canvasRef.current.width = width;
      canvasRef.current.height = height;

      // Draw Video
      context.drawImage(videoRef.current, 0, 0, width, height);

      // Add Watermark
      const gradient = context.createLinearGradient(0, height - 120, 0, height);
      gradient.addColorStop(0, "transparent");
      gradient.addColorStop(1, "rgba(0,0,0,0.8)");
      context.fillStyle = gradient;
      context.fillRect(0, height - 120, width, 120);

      const now = new Date();
      context.shadowColor = "rgba(0,0,0,0.5)";
      context.shadowBlur = 4;
      context.fillStyle = "white";
      const fontStack = "'SimHei', 'Heiti SC', 'Microsoft YaHei', sans-serif";
      const timeStr = now.toLocaleTimeString('zh-CN', { hour12: false });
      const timeFontSize = Math.max(32, width / 12); 
      context.font = `bold ${timeFontSize}px ${fontStack}`;
      context.textAlign = "right";
      context.fillText(timeStr, width - 20, height - 30);
      const dateStr = now.toLocaleDateString('zh-CN', { year: 'numeric', month: 'long', day: 'numeric', weekday: 'short' });
      context.font = `bold 20px ${fontStack}`;
      context.fillText(dateStr, width - 20, height - (timeFontSize + 20));

      const dataUrl = canvasRef.current.toDataURL('image/jpeg', 0.8); // 80% quality

      canvasRef.current.toBlob((blob) => {
        if (blob) resolve({ dataUrl, blob });
        else resolve(null);
      }, 'image/jpeg', 0.8);
    });
  };

  const handleClockAction = async () => {
    const clickTime = new Date(); 
    setLoading(true);

    const photoData = await capturePhotoData();

    // BACKEND INTEGRATION NOTE:
    // Here you would typically call `api.upload('/upload/attendance', photoData.blob)`
    // and receive a cloud URL (e.g., https://oss.example.com/photo123.jpg) back.
    // For now, we still pass the DataURL to maintain current functionality.

    // Simulate network delay
    await new Promise(resolve => setTimeout(resolve, 800));

    if (photoData) {
      if (status === AttendanceStatus.CLOCKED_OUT) {
        const resultStatus = calculateAttendanceStatus('IN', clickTime, config);
        onClockIn(photoData.dataUrl, resultStatus, clickTime.toISOString());
      } else {
        const resultStatus = calculateAttendanceStatus('OUT', clickTime, config);
        onClockOut(photoData.dataUrl, resultStatus, clickTime.toISOString());
      }
    } else {
      setError("拍照失败，请刷新重试。");
    }
    setLoading(false);
  };

  const getDayProgress = () => {
    const now = currentTime;
    const start = new Date(now).setHours(parseInt(config.startTime.split(':')[0]), 0, 0, 0);
    const end = new Date(now).setHours(parseInt(config.endTime.split(':')[0]), 0, 0, 0);
    const total = end - start;
    const current = now.getTime() - start;
    return Math.min(Math.max((current / total) * 100, 0), 100);
  };

  return (
    <div className="flex flex-col h-full">
      <div className="relative w-full flex-1 min-h-[300px] bg-black rounded-3xl overflow-hidden shadow-inner ring-1 ring-black/5 group">
        {!error ? (
          <>
            <video ref={videoRef} autoPlay muted playsInline className="w-full h-full object-cover transform scale-x-[-1] opacity-90 group-hover:opacity-100 transition-opacity" />
            <div className="absolute top-4 left-4 bg-black/40 backdrop-blur-md px-3 py-1 rounded-full flex items-center gap-2">
               <div className="w-2 h-2 bg-green-400 rounded-full animate-pulse"></div>
               <span className="text-[10px] font-medium text-white tracking-wider">摄像头就绪</span>
            </div>
            <div className="absolute bottom-4 left-4 right-4 flex justify-between items-end">
               <div>
                  <p className="text-white/80 text-xs font-medium tracking-widest uppercase mb-1">当前时间</p>
                  <p className="text-white text-3xl font-bold font-mono tracking-tighter leading-none">{currentTime.toLocaleTimeString([], { hour12: false })}</p>
               </div>
               <div className="text-right">
                  <p className="text-white/80 text-xs font-medium tracking-widest uppercase mb-1">当前状态</p>
                  <p className="text-white font-bold flex items-center gap-1 justify-end">
                     {status === AttendanceStatus.CLOCKED_OUT ? '未签到' : '工作中'}
                     {status === AttendanceStatus.CLOCKED_IN && <div className="w-2 h-2 bg-green-400 rounded-full"></div>}
                  </p>
               </div>
            </div>
          </>
        ) : (
           <div className="flex flex-col items-center justify-center h-full text-gray-500 p-6 text-center bg-gray-100">
              <AlertCircle size={32} className="text-red-400 mb-2" />
              <p className="text-sm font-medium text-gray-800">{error}</p>
              <button onClick={startCamera} className="mt-4 px-4 py-2 bg-white border border-gray-200 rounded-lg text-xs font-bold shadow-sm">重试</button>
           </div>
        )}
        <canvas ref={canvasRef} className="hidden" />
      </div>

      <div className="mt-6 mb-2 px-1">
         <div className="flex justify-between text-xs text-gray-400 font-medium mb-1.5 uppercase tracking-wider">
            <span>上班 {config.startTime}</span>
            <span>下班 {config.endTime}</span>
         </div>
         <div className="h-2 w-full bg-gray-100 rounded-full overflow-hidden">
            <div className="h-full bg-gradient-to-r from-blue-400 to-indigo-500 transition-all duration-1000" style={{ width: `${getDayProgress()}%` }}></div>
         </div>
      </div>

      <div className="mt-4">
        <button
          onClick={handleClockAction}
          disabled={loading || !!error}
          className={`w-full py-4 rounded-2xl font-black text-lg text-white shadow-lg transform transition-all active:scale-[0.98] disabled:opacity-70 disabled:cursor-not-allowed flex items-center justify-center gap-3 relative overflow-hidden group
            ${status === AttendanceStatus.CLOCKED_OUT ? 'bg-gray-900 hover:bg-black shadow-gray-200' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200'}`}
        >
          {loading ? <Clock className="animate-spin" size={24} /> : (
             <>
                {status === AttendanceStatus.CLOCKED_OUT ? <Clock size={20} className="group-hover:scale-110 transition-transform" /> : <CheckCircle2 size={20} />}
                <span>{status === AttendanceStatus.CLOCKED_OUT ? '上班打卡 (Clock In)' : '下班打卡 (Clock Out)'}</span>
             </>
          )}
        </button>
        <p className="text-center text-xs text-gray-400 mt-2">点击按钮以确认记录当前时间</p>
      </div>
    </div>
  );
};

export default Attendance;

import React, { useState, useMemo } from 'react';
import { 
  LayoutDashboard, 
  UserPlus, 
  ClipboardList, 
  TrendingUp,
  PieChart,
  BarChart3,
  UserCheck
} from 'lucide-react';
import { QueueTicket, RegistrationRecord, Staff, FormTemplate, FormSubmission, PermissionSettings, UserSession, RegistrationConfig } from '../types';
import StaffRegistration from './StaffRegistration';
import { ResponsiveContainer, PieChart as RePieChart, Pie, Cell, Tooltip, Legend, BarChart, Bar, XAxis, YAxis, CartesianGrid } from 'recharts';

interface TrainingCheckinManagerProps {
  queue: QueueTicket[];
  registrationList: RegistrationRecord[];
  onSiteRecords: RegistrationRecord[]; 
  onUpdateOnSiteRecords: (records: RegistrationRecord[]) => void;
  staffList: Staff[];
  forms: FormTemplate[];
  formSubmissions: FormSubmission[];
  onUpdateRegistration: (records: RegistrationRecord[]) => void;
  onBatchAddStaff: (staffList: Staff[]) => void;
  onManageForm?: (formId: string, mode: 'EDIT' | 'ANALYTICS' | 'PREVIEW') => void;
  permissionSettings: PermissionSettings;
  session: UserSession | null;
  registrationConfig: RegistrationConfig;
}

const TrainingCheckinManager: React.FC<TrainingCheckinManagerProps> = ({
  queue,
  registrationList,
  onSiteRecords,
  onUpdateOnSiteRecords,
  staffList,
  forms,
  formSubmissions,
  onUpdateRegistration,
  onBatchAddStaff,
  onManageForm,
  permissionSettings,
  session,
  registrationConfig
}) => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'MASTER_LIST' | 'ONSITE'>('DASHBOARD');

  // STRICT PERMISSION: Only ADMIN sees Master List & On-Site Registration.
  const isAdmin = session?.role === 'ADMIN';
  const showMasterList = isAdmin;
  const showOnSite = isAdmin;

  // --- Statistics Logic ---
  const dashboardStats = useMemo(() => {
    // 1. Total Check-ins
    const checkInCount = queue.length;

    // 2. Total Registered (Master + OnSite) - Deduplicated by ID
    const allIds = new Set([...registrationList.map(r => r.id), ...onSiteRecords.map(r => r.id)]);
    const totalRegistered = allIds.size;

    // 3. Gender Distribution of CHECKED-IN users
    let maleCount = 0;
    let femaleCount = 0;

    // Helper to find person details
    const findPerson = (id: string) => {
      return registrationList.find(r => r.id === id) || 
             onSiteRecords.find(r => r.id === id) || 
             staffList.find(s => s.id === id);
    };

    queue.forEach(ticket => {
      const person = findPerson(ticket.staffId);
      if (person) {
        const g = (person as any).gender; 
        if (g === '男' || g === 'Male') maleCount++;
        else if (g === '女' || g === 'Female') femaleCount++;
      }
    });

    // 4. Check-in Timeline
    const timelineData: Record<string, number> = {};
    queue.forEach(t => {
       if(t.checkInTime) {
         const hour = new Date(t.checkInTime).getHours();
         const key = `${hour}:00`;
         timelineData[key] = (timelineData[key] || 0) + 1;
       }
    });
    const timelineChartData = Object.keys(timelineData).map(k => ({ name: k, count: timelineData[k] })).sort((a,b) => parseInt(a.name) - parseInt(b.name));

    return {
      checkInCount,
      totalRegistered,
      checkInRate: totalRegistered > 0 ? Math.round((checkInCount / totalRegistered) * 100) : 0,
      genderData: [
        { name: '男', value: maleCount },
        { name: '女', value: femaleCount }
      ],
      timelineChartData,
      maleCount,
      femaleCount
    };
  }, [queue, registrationList, onSiteRecords, staffList]);

  const COLORS = ['#3b82f6', '#ec4899', '#9ca3af'];

  // Construct tabs dynamically
  const tabs = [
    { id: 'DASHBOARD', label: '数据看板', icon: LayoutDashboard },
  ];

  if (showOnSite) {
    tabs.push({ id: 'ONSITE', label: '现场报名录入', icon: UserPlus });
  }

  if (showMasterList) {
    tabs.push({ id: 'MASTER_LIST', label: '汇总名单管理', icon: ClipboardList });
  }

  return (
    <div className="space-y-4 md:space-y-6 animate-fade-in pb-20">

      {/* Tab Navigation */}
      <div className="bg-white p-2 rounded-xl shadow-sm border border-gray-100">
         <div className="flex p-1 bg-gray-100/80 rounded-lg overflow-x-auto w-full no-scrollbar">
            {tabs.map(tab => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={`flex-1 min-w-[100px] flex items-center justify-center gap-2 px-4 py-2.5 rounded-md text-sm font-bold transition-all whitespace-nowrap ${
                  activeTab === tab.id 
                    ? 'bg-white text-indigo-600 shadow-sm' 
                    : 'text-gray-500 hover:text-gray-700 hover:bg-gray-200/50'
                }`}
              >
                <tab.icon size={16} /> {tab.label}
              </button>
            ))}
         </div>
      </div>

      {/* --- DASHBOARD VIEW --- */}
      {activeTab === 'DASHBOARD' && (
        <div className="space-y-4 md:space-y-6">
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
              <div className="bg-white p-5 rounded-xl border border-gray-100 shadow-sm">
                 <div className="flex justify-between items-start mb-2">
                    <p className="text-xs font-bold text-gray-400 uppercase">已签到人数</p>
                    <div className="p-2 bg-green-50 text-green-600 rounded-lg"><UserCheck size={16} /></div>
                 </div>
                 <h3 className="text-3xl font-black text-gray-800">{dashboardStats.checkInCount}</h3>
                 <p className="text-xs text-gray-400 mt-1">签到率 {dashboardStats.checkInRate}%</p>
              </div>

              {showOnSite && (
                <div className="bg-white p-5 rounded-xl border border-gray-100 shadow-sm">
                   <div className="flex justify-between items-start mb-2">
                      <p className="text-xs font-bold text-gray-400 uppercase">现场报名</p>
                      <div className="p-2 bg-blue-50 text-blue-600 rounded-lg"><UserPlus size={16} /></div>
                   </div>
                   <h3 className="text-3xl font-black text-gray-800">{onSiteRecords.length}</h3>
                   <p className="text-xs text-gray-400 mt-1">今日新增录入</p>
                </div>
              )}

              {showMasterList && (
                <div className="bg-white p-5 rounded-xl border border-gray-100 shadow-sm">
                   <div className="flex justify-between items-start mb-2">
                      <p className="text-xs font-bold text-gray-400 uppercase">总名单人数</p>
                      <div className="p-2 bg-indigo-50 text-indigo-600 rounded-lg"><ClipboardList size={16} /></div>
                   </div>
                   <h3 className="text-3xl font-black text-gray-800">{registrationList.length}</h3>
                   <p className="text-xs text-gray-400 mt-1">包含所有渠道数据</p>
                </div>
              )}
              <div className="bg-white p-5 rounded-xl border border-gray-100 shadow-sm">
                 <div className="flex justify-between items-start mb-2">
                    <p className="text-xs font-bold text-gray-400 uppercase">待签到</p>
                    <div className="p-2 bg-orange-50 text-orange-600 rounded-lg"><TrendingUp size={16} /></div>
                 </div>
                 <h3 className="text-3xl font-black text-gray-800">{dashboardStats.totalRegistered - dashboardStats.checkInCount}</h3>
                 <p className="text-xs text-gray-400 mt-1">剩余未到场</p>
              </div>
           </div>

           <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              {/* Gender Chart */}
              <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm">
                 <h3 className="font-bold text-gray-800 mb-6 flex items-center gap-2">
                    <PieChart size={18} className="text-pink-500" /> 签到人员性别分布
                 </h3>
                 <div className="h-64 flex items-center justify-center">
                    {dashboardStats.checkInCount > 0 ? (
                      <ResponsiveContainer width="100%" height="100%">
                          <RePieChart>
                            <Pie
                                data={dashboardStats.genderData}
                                cx="50%"
                                cy="50%"
                                innerRadius={60}
                                outerRadius={80}
                                paddingAngle={5}
                                dataKey="value"
                            >
                                {dashboardStats.genderData.map((entry, index) => (
                                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                ))}
                            </Pie>
                            <Tooltip />
                            <Legend verticalAlign="bottom" height={36} iconType="circle" />
                          </RePieChart>
                      </ResponsiveContainer>
                    ) : (
                      <div className="text-gray-400 flex flex-col items-center">
                        <PieChart size={48} className="mb-2 opacity-20" />
                        <p>暂无签到数据</p>
                      </div>
                    )}
                 </div>
              </div>

              {/* Timeline Chart */}
              <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm">
                 <h3 className="font-bold text-gray-800 mb-6 flex items-center gap-2">
                    <BarChart3 size={18} className="text-indigo-500" /> 签到时间段分布
                 </h3>
                 <div className="h-64">
                    {dashboardStats.timelineChartData.length > 0 ? (
                      <ResponsiveContainer width="100%" height="100%">
                          <BarChart data={dashboardStats.timelineChartData}>
                            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f3f4f6" />
                            <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 12, fill: '#9ca3af'}} />
                            <YAxis axisLine={false} tickLine={false} tick={{fontSize: 12, fill: '#9ca3af'}} />
                            <Tooltip cursor={{fill: '#f3f4f6'}} contentStyle={{borderRadius: '8px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)'}} />
                            <Bar dataKey="count" fill="#6366f1" radius={[4, 4, 0, 0]} barSize={20} />
                          </BarChart>
                      </ResponsiveContainer>
                    ) : (
                      <div className="h-full flex flex-col items-center justify-center text-gray-400">
                        <BarChart3 size={48} className="mb-2 opacity-20" />
                        <p>暂无签到数据</p>
                      </div>
                    )}
                 </div>
              </div>
           </div>
        </div>
      )}

      {/* --- ON-SITE REGISTRATION VIEW (ADMIN ONLY) --- */}
      {activeTab === 'ONSITE' && showOnSite && (
        <StaffRegistration 
          records={onSiteRecords} 
          onUpdateRecords={onUpdateOnSiteRecords} 
          groups={[]} 
          onBatchAddStaff={onBatchAddStaff} 
          existingStaffList={staffList} 
          forms={forms}
          formSubmissions={formSubmissions}
          onManageForm={onManageForm}
          permissionSettings={permissionSettings}
          displayMode="MASTER" 
          allowFormSync={false} 
          allowExcelImport={false} 
          allowManualEntry={true}
          idPrefix={registrationConfig.onSitePrefix} 
        />
      )}

      {/* --- MASTER LIST VIEW (ADMIN ONLY) --- */}
      {activeTab === 'MASTER_LIST' && showMasterList && (
        <StaffRegistration 
          records={registrationList} 
          onUpdateRecords={onUpdateRegistration} 
          groups={[]} 
          onBatchAddStaff={onBatchAddStaff} 
          existingStaffList={staffList} 
          forms={forms}
          formSubmissions={formSubmissions}
          onManageForm={onManageForm}
          permissionSettings={permissionSettings}
          displayMode="ALL"
          idPrefix={registrationConfig.masterPrefix} 
        />
      )}

    </div>
  );
};

