import React, { useState, useEffect, useMemo } from 'react';
import { 
  Staff, 
  QueueTicket, 
  RegistrationRecord, 
  AttendanceRecord, 
  Group, 
  Announcement, 
  FormTemplate, 
  FormSubmission, 
  AdminUser, 
  AttendanceConfig, 
  PermissionSettings, 
  LoginConfig, 
  RegistrationConfig, 
  UserSession 
} from './types';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import StaffDashboard from './components/StaffDashboard';
import IntervieweeDashboard from './components/IntervieweeDashboard';
import TrainingCheckinManager from './components/TrainingCheckinManager';
import OutsourcedManager from './components/OutsourcedManager';
import FormManager from './components/FormManager';
import FormDesigner from './components/FormDesigner';
import FormAnalytics from './components/FormAnalytics';
import FormShareDashboard from './components/FormShareDashboard';
import SystemSettings from './components/SystemSettings';
import CheckInSystem from './components/CheckInSystem';
import PublicDynamicForm from './components/PublicDynamicForm';
import { LayoutDashboard, Users, ClipboardList, Settings, ScanLine, FileText, LogOut, Menu } from 'lucide-react';

const load = (key: string, def: any) => {
  const s = localStorage.getItem(key);
  try {
    return s ? JSON.parse(s) : def;
  } catch (e) {
    return def;
  }
};

export default function App() {
  const [isLoading, setIsLoading] = useState(true);

  // -- Data State --
  const [session, setSession] = useState<UserSession | null>(() => {
    return load('userSession', null);
  });

  const [queueData, setQueueData] = useState<QueueTicket[]>([]);
  const [attendanceRecords, setAttendanceRecords] = useState<AttendanceRecord[]>([]);
  const [registrationList, setRegistrationList] = useState<RegistrationRecord[]>([]);
  const [onSiteRecords, setOnSiteRecords] = useState<RegistrationRecord[]>([]);
  const [staffList, setStaffList] = useState<Staff[]>([]);
  const [groups, setGroups] = useState<Group[]>([]);
  const [announcements, setAnnouncements] = useState<Announcement[]>([]);

  const [forms, setForms] = useState<FormTemplate[]>([]);
  const [formSubmissions, setFormSubmissions] = useState<FormSubmission[]>([]);
  const [adminUsers, setAdminUsers] = useState<AdminUser[]>([]);

  const [systemDomain, setSystemDomain] = useState<string>('');
  const [attendanceConfig, setAttendanceConfig] = useState<AttendanceConfig>({ startTime: '09:00', endTime: '18:00', overtimeStart: '19:00' });
  const [permissionSettings, setPermissionSettings] = useState<PermissionSettings>({ allowLeaderExport: true, allowLeaderBroadcast: true, allowStaffViewTeam: false, showSensitiveInfo: true, enableCheckIn: true });
  const [loginConfig, setLoginConfig] = useState<LoginConfig>({ title: 'STAFFTool', subtitle: '', imageUrl: '', logoUrl: '', enableCandidateLogin: true });
  const [registrationConfig, setRegistrationConfig] = useState<RegistrationConfig>({ masterPrefix: 'M', onSitePrefix: 'S' });

  // -- UI State --
  const [activeAdminTab, setActiveAdminTab] = useState('DASHBOARD');
  const [activeFormId, setActiveFormId] = useState<string | null>(null);
  const [formViewMode, setFormViewMode] = useState<'LIST' | 'EDIT' | 'ANALYTICS' | 'SHARE' | 'PREVIEW'>('LIST');

  // Initial Load
  useEffect(() => {
    const refreshData = () => {
      setQueueData(load('queueData', []));
      setAttendanceRecords(load('attendanceRecords', []));
      setRegistrationList(load('registrationList', []));
      setOnSiteRecords(load('onSiteRecords', []));
      setStaffList(load('staffList', []));
      setGroups(load('groups', []));
      setAnnouncements(load('announcements', []));
      setForms(load('forms', []));
      setFormSubmissions(load('formSubmissions', []));
      setAdminUsers(load('adminUsers', [{ username: 'admin', password: 'password' }]));

      const savedDomain = localStorage.getItem('systemDomain');
      try {
         setSystemDomain(savedDomain ? JSON.parse(savedDomain) : 'https://workpulse.app');
      } catch (e) {
         setSystemDomain(savedDomain || 'https://workpulse.app');
      }

      setAttendanceConfig(load('attendanceConfig', { startTime: '09:00', endTime: '18:00', overtimeStart: '19:00' }));
      setPermissionSettings(load('permissionSettings', { allowLeaderExport: true, allowLeaderBroadcast: true, allowStaffViewTeam: false, showSensitiveInfo: true, enableCheckIn: true }));
      setLoginConfig(load('loginConfig', { title: 'STAFFTool', subtitle: '', imageUrl: '', logoUrl: '', enableCandidateLogin: true }));
      setRegistrationConfig(load('registrationConfig', { masterPrefix: 'M', onSitePrefix: 'S' }));

      setIsLoading(false);
    };

    refreshData();
  }, []);

  // -- Data Sync --
  useEffect(() => {
    if (isLoading) return;

    const syncStateFromStorage = () => {
      const syncItem = (key: string, setter: React.Dispatch<React.SetStateAction<any>>) => {
        const saved = localStorage.getItem(key);
        if (saved) {
          try {
            const parsed = JSON.parse(saved);
            setter((prev: any) => {
              if (JSON.stringify(prev) !== saved) {
                return parsed;
              }
              return prev;
            });
          } catch(e) { console.error('Sync parse error', e); }
        }
      };

      syncItem('queueData', setQueueData);
      syncItem('attendanceRecords', setAttendanceRecords);
      syncItem('registrationList', setRegistrationList);
      syncItem('onSiteRecords', setOnSiteRecords);
      syncItem('staffList', setStaffList);
      syncItem('groups', setGroups);
      syncItem('announcements', setAnnouncements);
      syncItem('forms', setForms);
      syncItem('formSubmissions', setFormSubmissions);
      syncItem('adminUsers', setAdminUsers);
      syncItem('attendanceConfig', setAttendanceConfig);
      syncItem('permissionSettings', setPermissionSettings);
      syncItem('loginConfig', setLoginConfig);
      syncItem('registrationConfig', setRegistrationConfig);
      syncItem('systemDomain', setSystemDomain);
    };

    window.addEventListener('storage', syncStateFromStorage);
    const intervalId = setInterval(syncStateFromStorage, 2000);

    return () => {
      window.removeEventListener('storage', syncStateFromStorage);
      clearInterval(intervalId);
    };
  }, [isLoading]);

  // -- Persistence --
  useEffect(() => { if(!isLoading) localStorage.setItem('userSession', JSON.stringify(session)); }, [session, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('staffList', JSON.stringify(staffList)); }, [staffList, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('queueData', JSON.stringify(queueData)); }, [queueData, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('announcements', JSON.stringify(announcements)); }, [announcements, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('registrationList', JSON.stringify(registrationList)); }, [registrationList, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('onSiteRecords', JSON.stringify(onSiteRecords)); }, [onSiteRecords, isLoading]); 
  useEffect(() => { if(!isLoading) localStorage.setItem('attendanceRecords', JSON.stringify(attendanceRecords)); }, [attendanceRecords, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('groups', JSON.stringify(groups)); }, [groups, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('forms', JSON.stringify(forms)); }, [forms, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('formSubmissions', JSON.stringify(formSubmissions)); }, [formSubmissions, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('systemDomain', JSON.stringify(systemDomain)); }, [systemDomain, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('attendanceConfig', JSON.stringify(attendanceConfig)); }, [attendanceConfig, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('permissionSettings', JSON.stringify(permissionSettings)); }, [permissionSettings, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('adminUsers', JSON.stringify(adminUsers)); }, [adminUsers, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('loginConfig', JSON.stringify(loginConfig)); }, [loginConfig, isLoading]);
  useEffect(() => { if(!isLoading) localStorage.setItem('registrationConfig', JSON.stringify(registrationConfig)); }, [registrationConfig, isLoading]);

  // -- Handlers --

  const handleLogin = (userId: string, role: 'ADMIN' | 'USER') => {
    if (role === 'USER') {
       const staff = staffList.find(s => s.id === userId);
       if (!staff) {
          // Check registration for candidates
          const candidate = registrationList.find(r => r.id === userId) || onSiteRecords.find(r => r.id === userId);
          if (candidate) {
              setSession({ userId, role, staff: {
                  id: candidate.id,
                  name: candidate.name,
                  idCard: candidate.idCard || '',
                  phone: candidate.phone,
                  avatar: '',
                  status: 'PENDING', // Treat as pending/interviewee
                  roles: [],
                  joinDate: new Date().toISOString(),
                  registrationNumber: candidate.registrationNumber
              }});
          }
       } else {
          setSession({ userId, role, staff });
       }
    } else {
       setSession({ userId, role });
    }
  };

  const handleLogout = () => {
    setSession(null);
    setActiveAdminTab('DASHBOARD');
  };

  // Helper for forms
  const activeForm = useMemo(() => forms.find(f => f.id === activeFormId), [forms, activeFormId]);
  const activeSubmissions = useMemo(() => formSubmissions.filter(s => s.formId === activeFormId), [formSubmissions, activeFormId]);

  if (isLoading) return <div className="min-h-screen flex items-center justify-center bg-gray-50">Loading...</div>;

  // -- Views --

  if (!session) {
    return (
      <Login 
        staffList={staffList}
        registrationList={[...registrationList, ...onSiteRecords]}
        onLogin={handleLogin}
        adminUsers={adminUsers}
        loginConfig={loginConfig}
      />
    );
  }

  // USER VIEW
  if (session.role === 'USER') {
     const currentUser = session.staff || staffList.find(s => s.id === session.userId);
     if (!currentUser) return <div className="p-10">User not found</div>;

     // Interviewee / Candidate View
     if (currentUser.status === 'PENDING' || currentUser.status === 'INTERVIEWED' || currentUser.status === 'REJECTED') {
        const myTicket = queueData.find(q => q.staffId === currentUser.id);
        const myIndex = queueData.findIndex(q => q.staffId === currentUser.id);
        const ticketsAhead = myIndex > -1 ? myIndex : 0; // Simplified logic

        return (
          <IntervieweeDashboard 
             staff={currentUser}
             myTicket={myTicket}
             ticketsAhead={ticketsAhead}
             onLogout={handleLogout}
          />
        );
     }

     // Active Staff View
     const myGroup = groups.find(g => currentUser.roles.some(r => r.groupId === g.id));
     const groupLeaders = staffList.filter(s => s.status === 'ACTIVE' && s.roles.some(r => r.groupId === myGroup?.id && r.isLeader));
     const myAttendanceStatus = attendanceRecords
        .filter(r => r.staffId === currentUser.id)
        .sort((a,b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime())[0]?.type === 'IN' ? 'CLOCKED_IN' : 'CLOCKED_OUT';

     const myHistory = attendanceRecords.filter(r => r.staffId === currentUser.id);

     return (
       <div className="min-h-screen bg-gray-50">
          <header className="bg-white border-b border-gray-200 px-4 py-3 flex justify-between items-center sticky top-0 z-20">
             <div className="flex items-center gap-3">
               {loginConfig.logoUrl && <img src={loginConfig.logoUrl} className="h-8 w-auto" alt="Logo" />}
               <span className="font-bold text-gray-800">{loginConfig.title}</span>
             </div>
             <button onClick={handleLogout} className="text-sm font-medium text-gray-500 hover:text-red-500 flex items-center gap-1">
               <LogOut size={16} /> 退出
             </button>
          </header>
          <StaffDashboard 
             currentUser={currentUser}
             group={myGroup}
             leaders={groupLeaders}
             staffList={staffList}
             announcements={announcements}
             attendanceStatus={myAttendanceStatus as any}
             attendanceHistory={myHistory}
             attendanceConfig={attendanceConfig}
             onClockIn={(photo, status, ts) => {
                const newRecord: AttendanceRecord = {
                   id: crypto.randomUUID(),
                   staffId: currentUser.id,
                   timestamp: ts,
                   type: 'IN',
                   photoUrl: photo,
                   status,
                   location: 'Office'
                };
                setAttendanceRecords(prev => [newRecord, ...prev]);
             }}
             onClockOut={(photo, status, ts) => {
                const newRecord: AttendanceRecord = {
                   id: crypto.randomUUID(),
                   staffId: currentUser.id,
                   timestamp: ts,
                   type: 'OUT',
                   photoUrl: photo,
                   status,
                   location: 'Office'
                };
                setAttendanceRecords(prev => [newRecord, ...prev]);
             }}
          />
       </div>
     );
  }

  // ADMIN VIEW
  const AdminSidebarItem = ({ id, label, icon: Icon }: any) => (
    <button
      onClick={() => setActiveAdminTab(id)}
      className={`w-full flex items-center gap-3 px-4 py-3 text-sm font-bold transition-all rounded-xl ${
        activeAdminTab === id 
          ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' 
          : 'text-gray-500 hover:bg-gray-100 hover:text-gray-900'
      }`}
    >
      <Icon size={18} />
      <span className="hidden md:inline">{label}</span>
    </button>
  );

  return (
    <div className="flex h-screen bg-gray-50 font-sans overflow-hidden">
      {/* Sidebar */}
      <div className="w-20 md:w-64 bg-white border-r border-gray-200 flex flex-col justify-between shrink-0 z-30">
        <div>
           <div className="h-16 flex items-center justify-center md:justify-start md:px-6 border-b border-gray-100">
              {loginConfig.logoUrl ? (
                 <img src={loginConfig.logoUrl} className="h-8 w-auto" alt="Logo" />
              ) : (
                 <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold">W</div>
              )}
              <span className="ml-3 font-bold text-lg text-gray-800 hidden md:block">{loginConfig.title}</span>
           </div>

           <div className="p-4 space-y-2">
              <AdminSidebarItem id="DASHBOARD" label="概览看板" icon={LayoutDashboard} />
              <AdminSidebarItem id="REGISTRATION" label="报名与签到" icon={ClipboardList} />
              <AdminSidebarItem id="CHECKIN_SCANNER" label="核销终端" icon={ScanLine} />
              <AdminSidebarItem id="STAFF" label="人员管理" icon={Users} />
              <AdminSidebarItem id="FORMS" label="表单中心" icon={FileText} />
              <AdminSidebarItem id="SETTINGS" label="系统设置" icon={Settings} />
           </div>
        </div>

        <div className="p-4 border-t border-gray-100">
           <button 
             onClick={handleLogout}
             className="w-full flex items-center gap-3 px-4 py-3 text-sm font-bold text-red-500 hover:bg-red-50 rounded-xl transition-colors"
           >
              <LogOut size={18} />
              <span className="hidden md:inline">退出登录</span>
           </button>
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
         {/* Top Bar for Mobile Menu could go here */}
         <div className="flex-1 overflow-y-auto">
            {activeAdminTab === 'DASHBOARD' && (
               <div className="p-6 md:p-8">
                  <Dashboard 
                     attendanceRecords={attendanceRecords}
                     queueData={queueData}
                     announcements={announcements}
                     isAdmin={true}
                     staffList={staffList}
                     groups={groups}
                     currentUser={undefined} // Admin doesn't need staff context here usually
                  />
               </div>
            )}

            {activeAdminTab === 'REGISTRATION' && (
               <div className="p-6 md:p-8">
                  <TrainingCheckinManager 
                     queue={queueData}
                     registrationList={registrationList}
                     onSiteRecords={onSiteRecords}
                     onUpdateOnSiteRecords={setOnSiteRecords}
                     staffList={staffList}
                     forms={forms}
                     formSubmissions={formSubmissions}
                     onUpdateRegistration={setRegistrationList}
                     onBatchAddStaff={(newStaff) => setStaffList(prev => [...prev, ...newStaff])}
                     permissionSettings={permissionSettings}
                     session={session}
                     registrationConfig={registrationConfig}
                  />
               </div>
            )}

            {activeAdminTab === 'CHECKIN_SCANNER' && (
               <CheckInSystem 
                  queue={queueData}
                  registrationList={registrationList}
                  onSiteRecords={onSiteRecords}
                  staffList={staffList}
                  onCheckIn={(staffId) => {
                     // Check if already in queue
                     if (queueData.some(q => q.staffId === staffId)) return;

                     // Find user name
                     const user = registrationList.find(r => r.id === staffId) || onSiteRecords.find(r => r.id === staffId) || staffList.find(s => s.id === staffId);
                     if (!user) return;

                     const newTicket: QueueTicket = {
                        id: crypto.randomUUID(),
                        staffId: staffId,
                        staffName: user.name,
                        ticketNumber: `A${String(queueData.length + 1).padStart(3, '0')}`,
                        status: 'WAITING',
                        checkInTime: new Date().toISOString()
                     };
                     setQueueData(prev => [...prev, newTicket]);
                  }}
                  onClearQueue={() => setQueueData([])}
                  onUpdateTicketStatus={() => {}} 
               />
            )}

            {activeAdminTab === 'STAFF' && (
               <div className="p-6 md:p-8 h-full">
                  <OutsourcedManager 
                     staffList={staffList}
                     groups={groups}
                     registrationList={registrationList}
                     onSiteRecords={onSiteRecords}
                     permissionSettings={permissionSettings}
                     onUpdateStaff={(updated) => setStaffList(prev => prev.map(s => s.id === updated.id ? updated : s))}
                     onAddStaff={(newStaff) => setStaffList(prev => [...prev, newStaff])}
                     onBatchAddStaff={(list) => setStaffList(prev => [...prev, ...list])}
                     onAddGroup={(g) => setGroups(prev => [...prev, g])}
                     onUpdateGroup={(g) => setGroups(prev => prev.map(grp => grp.id === g.id ? g : grp))}
                     onDeleteGroup={(gid) => setGroups(prev => prev.filter(g => g.id !== gid))}
                  />
               </div>
            )}

            {activeAdminTab === 'FORMS' && (
               <div className="h-full bg-gray-50/50">
                  {formViewMode === 'LIST' && (
                     <div className="p-6 md:p-8">
                       <FormManager 
                          forms={forms}
                          onCreateForm={() => {
                             const newForm: FormTemplate = {
                                id: crypto.randomUUID(),
                                shareToken: Math.random().toString(36).substring(2, 10),
                                title: '未命名表单',
                                description: '',
                                status: 'DRAFT',
                                createdDate: new Date().toISOString().split('T')[0],
                                fields: [],
                                submissionCount: 0,
                                themeColor: 'blue'
                             };
                             setForms(prev => [...prev, newForm]);
                             setActiveFormId(newForm.id);
                             setFormViewMode('EDIT');
                          }}
                          onSelectForm={(id, action) => {
                             setActiveFormId(id);
                             setFormViewMode(action === 'SIMULATE' ? 'PREVIEW' : action); // Map SIMULATE to PREVIEW for internal consistency
                          }}
                          onDeleteForm={(id) => setForms(prev => prev.filter(f => f.id !== id))}
                          onToggleStatus={(id, status) => setForms(prev => prev.map(f => f.id === id ? { ...f, status } : f))}
                       />
                     </div>
                  )}

                  {formViewMode === 'EDIT' && activeForm && (
                     <FormDesigner 
                        form={activeForm}
                        onSave={(updated) => setForms(prev => prev.map(f => f.id === updated.id ? updated : f))}
                        onBack={() => setFormViewMode('LIST')}
                        onPublish={() => setFormViewMode('SHARE')}
                     />
                  )}

                  {formViewMode === 'ANALYTICS' && activeForm && (
                     <FormAnalytics 
                        form={activeForm}
                        submissions={activeSubmissions}
                        onDeleteSubmission={(sid) => setFormSubmissions(prev => prev.filter(s => s.id !== sid))}
                        onBack={() => setFormViewMode('LIST')}
                        onShare={() => setFormViewMode('SHARE')}
                     />
                  )}

                  {formViewMode === 'SHARE' && activeForm && (
                     <FormShareDashboard 
                        form={activeForm}
                        onBack={() => setFormViewMode('LIST')}
                        onPreview={() => setFormViewMode('PREVIEW')}
                        customDomain={systemDomain}
                     />
                  )}

                  {formViewMode === 'PREVIEW' && activeForm && (
                     <PublicDynamicForm 
                        form={activeForm}
                        onSubmit={(sub) => {
                           setFormSubmissions(prev => [...prev, sub]);
                           setForms(prev => prev.map(f => f.id === sub.formId ? { ...f, submissionCount: f.submissionCount + 1 } : f));
                        }}
                        onCancel={() => setFormViewMode('LIST')}
                     />
                  )}
               </div>
            )}

            {activeAdminTab === 'SETTINGS' && (
               <div className="p-6 md:p-8">
                  <SystemSettings 
                     initialDomain={systemDomain}
                     initialAttendanceConfig={attendanceConfig}
                     initialPermissionSettings={permissionSettings}
                     initialLoginConfig={loginConfig}
                     initialRegistrationConfig={registrationConfig}
                     adminUsers={adminUsers}
                     onSave={(settings) => {
                        setSystemDomain(settings.domain);
                        setAttendanceConfig(settings.attendance);
                        setPermissionSettings(settings.permissions);
                        setLoginConfig(settings.loginConfig);
                        setRegistrationConfig(settings.registrationConfig);
                     }}
                     onAddAdmin={(u) => {
                        if(adminUsers.some(a => a.username === u.username)) {
                           alert('用户名已存在');
                           return false;
                        }
                        setAdminUsers(prev => [...prev, u]);
                        return true;
                     }}
                     onDeleteAdmin={(username) => {
                        if(adminUsers.length <= 1) {
                           alert('必须保留至少一个管理员');
                           return;
                        }
                        setAdminUsers(prev => prev.filter(u => u.username !== username));
                     }}
                     onUpdateAdminPassword={(username, pass) => {
                        setAdminUsers(prev => prev.map(u => u.username === username ? {...u, password: pass} : u));
                     }}
                  />
               </div>
            )}
         </div>
      </div>
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { Staff, RegistrationRecord, FormTemplate, FormSubmission, PermissionSettings, Group } from '../types';
import { Search, UserPlus, CheckSquare, Square, Filter, FileSpreadsheet, Download } from 'lucide-react';
import { maskPhone, maskIdCard } from '../utils';

interface StaffRegistrationProps {
  records: RegistrationRecord[];
  onUpdateRecords: (records: RegistrationRecord[]) => void;
  groups: Group[];
  onBatchAddStaff: (staffList: Staff[]) => void;
  existingStaffList: Staff[];
  forms: FormTemplate[];
  formSubmissions: FormSubmission[];
  onManageForm?: (formId: string, mode: 'EDIT' | 'ANALYTICS' | 'PREVIEW') => void;
  permissionSettings: PermissionSettings;
  displayMode: 'MASTER' | 'ALL' | 'ONSITE';
  idPrefix: string;
  allowFormSync?: boolean;
  allowExcelImport?: boolean;
  allowManualEntry?: boolean;
}

const StaffRegistration: React.FC<StaffRegistrationProps> = ({ 
  records, onUpdateRecords, groups, onBatchAddStaff, existingStaffList, 
  forms, formSubmissions, onManageForm, permissionSettings, displayMode, idPrefix 
}) => {
  const [selectedRecordIds, setSelectedRecordIds] = useState<Set<string>>(new Set());
  const [searchTerm, setSearchTerm] = useState('');

  const displayRecords = useMemo(() => {
    const term = searchTerm.toLowerCase();
    return records.filter(r => 
        r.name.toLowerCase().includes(term) || 
        (r.phone && r.phone.includes(term)) ||
        (r.registrationNumber && r.registrationNumber.toLowerCase().includes(term))
    );
  }, [records, searchTerm]);

  const toggleSelectAll = () => {
    if (selectedRecordIds.size === displayRecords.length) {
      setSelectedRecordIds(new Set());
    } else {
      setSelectedRecordIds(new Set(displayRecords.map(r => r.id)));
    }
  };

  const toggleSelectOne = (id: string) => {
    const newSet = new Set(selectedRecordIds);
    if (newSet.has(id)) newSet.delete(id);
    else newSet.add(id);
    setSelectedRecordIds(newSet);
  };

  const handleBatchAddToStaff = () => {
       const newStaffList: Staff[] = [];

       displayRecords
         .filter(r => selectedRecordIds.has(r.id))
         .forEach(rec => {
            // Check if already exists in staff list (by phone or ID card) to prevent duplicates
            const exists = existingStaffList.some(s => s.id === rec.id || (s.phone && s.phone === rec.phone));

            if (!exists && rec.name && (rec.idCard || rec.phone)) {
               newStaffList.push({
                  id: rec.id || crypto.randomUUID(), // Use existing ID if possible to link back
                  name: rec.name,
                  idCard: rec.idCard || rec.phone || '', 
                  phone: rec.phone || '',
                  avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${rec.name}`,
                  status: 'ACTIVE',
                  roles: [],
                  joinDate: new Date().toISOString().split('T')[0],
                  isTalent: false,
                  registrationNumber: rec.registrationNumber // Preserving the registration ID
               });
            }
         });

       if (newStaffList.length > 0) {
           onBatchAddStaff(newStaffList);
           alert(`成功添加 ${newStaffList.length} 名人员到员工库`);
           setSelectedRecordIds(new Set());
       } else {
           alert("未选择有效人员或所选人员已在员工库中");
       }
  };

  const exportToCSV = () => {
     const headers = ['编号', '姓名', '电话', '证件号', '提交时间', '状态'];
     const rows = displayRecords.map(r => [
        r.registrationNumber,
        r.name,
        r.phone || '',
        r.idCard || '',
        r.submissionTime,
        existingStaffList.some(s => s.id === r.id) ? '已录入' : '未录入'
     ]);

     const csvContent = "\ufeff" + [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
     const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
     const link = document.createElement('a');
     link.href = URL.createObjectURL(blob);
     link.download = `名单导出_${new Date().toISOString().split('T')[0]}.csv`;
     document.body.appendChild(link);
     link.click();
     document.body.removeChild(link);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 flex flex-col h-[600px]">
        {/* Toolbar */}
        <div className="p-4 border-b border-gray-100 flex flex-col md:flex-row justify-between gap-4">
            <div className="flex items-center gap-2 w-full md:w-auto">
                <div className="relative flex-1 md:w-64">
                    <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                    <input 
                        type="text" 
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        placeholder="搜索姓名、手机或编号..."
                        className="w-full pl-9 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 text-sm"
                    />
                </div>
                <button className="p-2 bg-gray-50 border border-gray-200 rounded-lg hover:bg-white text-gray-500">
                    <Filter size={16} />
                </button>
            </div>

            <div className="flex gap-2">
                <button 
                    onClick={exportToCSV}
                    className="flex items-center gap-2 px-3 py-2 bg-white border border-gray-200 text-gray-700 rounded-lg text-sm font-bold hover:bg-gray-50"
                >
                    <Download size={16} /> 导出
                </button>
                <button 
                    onClick={handleBatchAddToStaff}
                    disabled={selectedRecordIds.size === 0}
                    className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg text-sm font-bold hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm shadow-indigo-200"
                >
                    <UserPlus size={16} /> 批量转入员工库
                </button>
            </div>
        </div>

        {/* Table */}
        <div className="flex-1 overflow-auto custom-scrollbar relative">
            <table className="w-full text-left text-sm">
                <thead className="bg-gray-50 sticky top-0 z-10 text-gray-500 font-bold border-b border-gray-200">
                    <tr>
                        <th className="p-4 w-12">
                            <button onClick={toggleSelectAll} className="flex items-center text-gray-400 hover:text-indigo-600">
                                {selectedRecordIds.size > 0 && selectedRecordIds.size === displayRecords.length 
                                    ? <CheckSquare size={18} className="text-indigo-600" /> 
                                    : <Square size={18} />}
                            </button>
                        </th>
                        <th className="p-4">编号</th>
                        <th className="p-4">姓名</th>
                        <th className="p-4">联系方式</th>
                        <th className="p-4">证件信息</th>
                        <th className="p-4">提交时间</th>
                        <th className="p-4">状态</th>
                    </tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
                    {displayRecords.length === 0 ? (
                        <tr>
                            <td colSpan={7} className="p-12 text-center text-gray-400">
                                <FileSpreadsheet size={48} className="mx-auto mb-4 opacity-20" />
                                <p>暂无数据</p>
                            </td>
                        </tr>
                    ) : (
                        displayRecords.map(record => {
                            const isSelected = selectedRecordIds.has(record.id);
                            const isAlreadyStaff = existingStaffList.some(s => s.id === record.id);

                            return (
                                <tr key={record.id} className={`hover:bg-gray-50 transition-colors ${isSelected ? 'bg-indigo-50/30' : ''}`}>
                                    <td className="p-4">
                                        <button onClick={() => toggleSelectOne(record.id)} className="flex items-center text-gray-400 hover:text-indigo-600">
                                            {isSelected ? <CheckSquare size={18} className="text-indigo-600" /> : <Square size={18} />}
                                        </button>
                                    </td>
                                    <td className="p-4 font-mono text-xs text-gray-500">{record.registrationNumber}</td>
                                    <td className="p-4 font-bold text-gray-800">{record.name}</td>
                                    <td className="p-4 font-mono text-gray-600">
                                        {permissionSettings.showSensitiveInfo ? record.phone : maskPhone(record.phone)}
                                    </td>
                                    <td className="p-4 font-mono text-gray-600">
                                        {permissionSettings.showSensitiveInfo ? record.idCard : maskIdCard(record.idCard)}
                                    </td>
                                    <td className="p-4 text-xs text-gray-500">
                                        {record.submissionTime.split('T')[0]}
                                    </td>
                                    <td className="p-4">
                                        {isAlreadyStaff ? (
                                            <span className="bg-green-100 text-green-700 px-2 py-0.5 rounded text-xs font-bold">已录入</span>
                                        ) : (
                                            <span className="bg-gray-100 text-gray-500 px-2 py-0.5 rounded text-xs font-bold">待录入</span>
                                        )}
                                    </td>
                                </tr>
                            );
                        })
                    )}
                </tbody>
            </table>
        </div>

        {/* Footer Stats */}
        <div className="p-3 border-t border-gray-100 bg-gray-50 text-xs text-gray-500 flex justify-between">
            <span>共 {displayRecords.length} 条记录</span>
            <span>已选 {selectedRecordIds.size} 条</span>
        </div>
    </div>
  );
};

export default StaffRegistration;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Staff, 
  QueueTicket, 
  RegistrationRecord, 
  AttendanceRecord, 
  Group, 
  Announcement, 
  FormTemplate, 
  FormSubmission, 
  AdminUser, 
  AttendanceConfig, 
  PermissionSettings, 
  LoginConfig, 
  RegistrationConfig, 
  UserSession 
} from './types';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import StaffDashboard from './components/StaffDashboard';
import AttendanceReports from './components/AttendanceReports';
import IntervieweeDashboard from './components/IntervieweeDashboard';
import TrainingCheckinManager from './components/TrainingCheckinManager';
import OutsourcedManager from './components/OutsourcedManager';
import FormManager from './components/FormManager';
import FormDesigner from './components/FormDesigner';
