  { id: 'a1', title: '关于中秋节放假的通知', content: '全体员工请注意，公司将于9月29日至10月6日放假，请提前安排好工作。祝大家节日快乐！', date: '2023-09-20', type: 'NOTICE', authorName: '管理员', isSticky: true },
];

