        />;
      default:
        return <div className="p-10 text-center text-gray-500">功能开发中...</div>;
    }
  };

  // ... (rest of the file remains unchanged)
  if (activeTab === 'public_view_simulation' && selectedFormId) {
     const form = forms.find(f => f.id === selectedFormId);
     if (form) return <PublicDynamicForm form={form} onSubmit={handleFormSubmit} onCancel={() => { if (session) { if (designerMode === 'PREVIEW') setActiveTab('form_designer'); else setActiveTab('form_manager'); } else setActiveTab('login'); }} />;
  }

  if (!session) return <Login staffList={staffList} registrationList={registrationList} onLogin={handleLogin} adminUsers={adminUsers} loginConfig={loginConfig} />;

