};

export default StaffRegistration;

import React, { useState, useRef, useEffect } from 'react';
import { FormTemplate, FormSubmission, FormField } from '../types';
import { 
  CheckCircle2, 
  ChevronRight, 
  Clock,
  Sparkles,
  AlertCircle,
  PenTool,
  RotateCcw,
  CreditCard,
  UserSquare,
  Mail,
  MapPin,
  FileText
} from 'lucide-react';

interface PublicDynamicFormProps {
  form: FormTemplate;
  onSubmit: (submission: FormSubmission) => void;
  onCancel: () => void;
}

const PublicDynamicForm: React.FC<PublicDynamicFormProps> = ({ 
  form, 
  onSubmit,
  onCancel
}) => {
  const [step, setStep] = useState<'FORM' | 'SUCCESS'>('FORM');
  const [formData, setFormData] = useState<Record<string, any>>({});
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState<Record<string, boolean>>({});
  const [focusedField, setFocusedField] = useState<string | null>(null);

  // Helper to update field data
  const handleChange = (fieldId: string, value: any) => {
    setFormData(prev => ({ ...prev, [fieldId]: value }));
    // Clear error if any
    if (errors[fieldId]) {
      setErrors(prev => ({ ...prev, [fieldId]: false }));
    }
  };

  const validate = () => {
    const newErrors: Record<string, boolean> = {};
    let isValid = true;

    form.fields.forEach(f => {
      if (f.required) {
        const val = formData[f.id];
        if (val === undefined || val === '' || (Array.isArray(val) && val.length === 0) || (typeof val === 'object' && Object.keys(val).length === 0)) {
          newErrors[f.id] = true;
          isValid = false;
        }
      }
    });

    setErrors(newErrors);
    return isValid;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!validate()) {
      alert("请填写所有必填项");
      // Scroll to first error
      const firstErrorId = form.fields.find(f => errors[f.id])?.id;
      if (firstErrorId) {
         document.getElementById(firstErrorId)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }
      return;
    }

    setLoading(true);

    // Simulate network request
    await new Promise(resolve => setTimeout(resolve, 800));

    const submission: FormSubmission = {
      id: crypto.randomUUID(),
      formId: form.id,
      submittedAt: new Date().toISOString(),
      data: formData
    };

    onSubmit(submission);
    setLoading(false);
    setStep('SUCCESS');
  };

  if (step === 'SUCCESS') {
    return (
      <div className="min-h-screen bg-[#F0F2F5] flex flex-col items-center justify-center p-4 font-sans">
        <div className="bg-white w-full max-w-md rounded-2xl shadow-xl p-10 text-center animate-in zoom-in duration-300">
          <div className="w-24 h-24 bg-green-50 rounded-full flex items-center justify-center mx-auto mb-6 animate-bounce-slow">
            <CheckCircle2 size={48} className="text-green-500" />
          </div>
          <h2 className="text-2xl font-bold text-gray-800 mb-3">提交成功</h2>
          <p className="text-gray-500 mb-8 leading-relaxed">
            您的信息已安全录入系统。<br/>感谢您的参与！
          </p>

          <button 
            onClick={onCancel}
            className="w-full bg-indigo-600 text-white py-3.5 rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200 active:scale-95"
          >
            返回表单中心 / 首页
          </button>
        </div>
      </div>
    );
  }

  // --- Signature Pad Component ---
  const SignaturePad = ({ value, onChange }: { value: string, onChange: (val: string) => void }) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const [isDrawing, setIsDrawing] = useState(false);

    // Initialize canvas context
    useEffect(() => {
        if (value && canvasRef.current) {
            // If there's an existing value (base64), we load it (simple implementation)
            const ctx = canvasRef.current.getContext('2d');
            const img = new Image();
            img.onload = () => ctx?.drawImage(img, 0, 0);
            img.src = value;
        }
    }, []);

    const getPos = (e: React.MouseEvent | React.TouchEvent) => {
        const canvas = canvasRef.current;
        if (!canvas) return { x: 0, y: 0 };
        const rect = canvas.getBoundingClientRect();
        const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
        const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;
        return {
            x: clientX - rect.left,
            y: clientY - rect.top
        };
    };

    const startDraw = (e: React.MouseEvent | React.TouchEvent) => {
        setIsDrawing(true);
        const ctx = canvasRef.current?.getContext('2d');
        if (!ctx) return;
        const { x, y } = getPos(e);
        ctx.beginPath();
        ctx.moveTo(x, y);
    };

    const draw = (e: React.MouseEvent | React.TouchEvent) => {
        if (!isDrawing) return;
        e.preventDefault(); // Prevent scrolling
        const ctx = canvasRef.current?.getContext('2d');
        if (!ctx) return;
        const { x, y } = getPos(e);
        ctx.lineTo(x, y);
        ctx.stroke();
    };

    const stopDraw = () => {
        if (isDrawing && canvasRef.current) {
            onChange(canvasRef.current.toDataURL());
        }
        setIsDrawing(false);
    };

    const clear = () => {
        const ctx = canvasRef.current?.getContext('2d');
        if (ctx && canvasRef.current) {
            ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
            onChange('');
        }
    };

    return (
        <div className="border-2 border-gray-200 border-dashed rounded-xl bg-gray-50 overflow-hidden relative">
            <canvas 
                ref={canvasRef}
                width={500}
                height={200}
                className="w-full h-40 touch-none cursor-crosshair bg-white"
                onMouseDown={startDraw}
                onMouseMove={draw}
                onMouseUp={stopDraw}
                onMouseLeave={stopDraw}
                onTouchStart={startDraw}
                onTouchMove={draw}
                onTouchEnd={stopDraw}
            />
            {!value && !isDrawing && (
                <div className="absolute inset-0 flex items-center justify-center pointer-events-none text-gray-300 gap-2">
                    <PenTool size={20} /> 请在此区域手写签名
                </div>
            )}
            <button 
                type="button"
                onClick={clear}
                className="absolute top-2 right-2 p-1.5 bg-gray-100 hover:bg-red-50 text-gray-500 hover:text-red-500 rounded shadow-sm z-10"
                title="清除重写"
            >
                <RotateCcw size={14} />
            </button>
        </div>
    );
  };

  // --- Field Renderer ---
  const renderField = (field: FormField, idx: number) => {
    const error = errors[field.id];
    const isFocused = focusedField === field.id;

    return (
      <div 
         key={field.id} 
         id={field.id}
         className={`space-y-3 transition-all duration-300 ${isFocused ? 'transform scale-[1.01]' : ''}`}
      >
         <label className={`block text-sm font-bold transition-colors ${error ? 'text-red-500' : isFocused ? 'text-indigo-600' : 'text-gray-700'}`}>
            {idx + 1}. {field.label} {field.required && <span className="text-red-500">*</span>}
         </label>

         {/* TEXT Input */}
         {field.type === 'TEXT' && (
           <div className={`relative rounded-xl border-2 transition-all ${error ? 'border-red-100 bg-red-50' : isFocused ? 'border-indigo-500 bg-white shadow-md shadow-indigo-50' : 'border-gray-100 bg-gray-50 hover:border-gray-300'}`}>
             <input 
               type="text" 
               value={formData[field.id] || ''}
               onChange={e => handleChange(field.id, e.target.value)}
               onFocus={() => setFocusedField(field.id)}
               onBlur={() => setFocusedField(null)}
               placeholder={field.placeholder || '请输入...'}
               className="w-full px-4 py-3.5 bg-transparent border-none focus:ring-0 outline-none text-gray-800 placeholder-gray-400"
             />
           </div>
         )}

         {/* ADDRESS Input */}
         {field.type === 'ADDRESS' && (
           <div className={`relative rounded-xl border-2 transition-all ${error ? 'border-red-100 bg-red-50' : isFocused ? 'border-indigo-500 bg-white shadow-md shadow-indigo-50' : 'border-gray-100 bg-gray-50 hover:border-gray-300'}`}>
             <div className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">
