                     {permissionSettings.allowLeaderBroadcast && <button onClick={() => setActiveTab('announcements')} className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl transition-all duration-200 mb-1 group ${activeTab === 'announcements' ? 'bg-gradient-to-r from-indigo-600 to-violet-600 text-white' : 'text-slate-400 hover:bg-white/5'}`}><Megaphone size={20} /> <span>发布公告</span></button>}
                   </>
