import React, { useState, useRef, useEffect } from 'react';
import { FormTemplate, FormSubmission, FormField } from '../types';
import { 
  CheckCircle2, 
  ChevronRight, 
  Clock,
  Sparkles,
  AlertCircle,
  PenTool,
  RotateCcw,
  CreditCard,
  UserSquare,
  Mail,
  MapPin,
  FileText,
  X
} from 'lucide-react';

interface PublicDynamicFormProps {
  form: FormTemplate;
  onSubmit: (submission: FormSubmission) => void;
  onCancel: () => void;
}

const PublicDynamicForm: React.FC<PublicDynamicFormProps> = ({ 
  form, 
  onSubmit,
  onCancel
}) => {
  const [formData, setFormData] = useState<Record<string, any>>({});
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState<Record<string, boolean>>({});
  const [focusedField, setFocusedField] = useState<string | null>(null);

  // Helper to update field data
  const handleChange = (fieldId: string, value: any) => {
    setFormData(prev => ({ ...prev, [fieldId]: value }));
    // Clear error if any
    if (errors[fieldId]) {
      setErrors(prev => ({ ...prev, [fieldId]: false }));
    }
  };

  const validate = () => {
    const newErrors: Record<string, boolean> = {};
    let isValid = true;

    form.fields.forEach(f => {
      if (f.required) {
        const val = formData[f.id];
        if (val === undefined || val === '' || (Array.isArray(val) && val.length === 0) || (typeof val === 'object' && Object.keys(val).length === 0)) {
          newErrors[f.id] = true;
          isValid = false;
        }
      }
    });

    setErrors(newErrors);
    return isValid;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!validate()) {
      alert("请填写所有必填项");
      // Scroll to first error
      const firstErrorId = form.fields.find(f => errors[f.id])?.id;
      if (firstErrorId) {
         document.getElementById(firstErrorId)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }
      return;
    }

    setLoading(true);

    // Simulate network request
    await new Promise(resolve => setTimeout(resolve, 800));

    const submission: FormSubmission = {
      id: crypto.randomUUID(),
      formId: form.id,
      submittedAt: new Date().toISOString(),
      data: formData
    };

    onSubmit(submission);
    setLoading(false);
    // Parent component handles the view transition
  };

  // --- Signature Pad Component ---
  const SignaturePad = ({ value, onChange }: { value: string, onChange: (val: string) => void }) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const [isDrawing, setIsDrawing] = useState(false);

    // Initialize canvas context
    useEffect(() => {
        if (value && canvasRef.current) {
            // If there's an existing value (base64), we load it (simple implementation)
            const ctx = canvasRef.current.getContext('2d');
            const img = new Image();
            img.onload = () => ctx?.drawImage(img, 0, 0);
            img.src = value;
        }
    }, []);

    const getPos = (e: React.MouseEvent | React.TouchEvent) => {
        const canvas = canvasRef.current;
        if (!canvas) return { x: 0, y: 0 };
        const rect = canvas.getBoundingClientRect();
        const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
        const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;
        return {
            x: clientX - rect.left,
            y: clientY - rect.top
        };
    };

    const startDraw = (e: React.MouseEvent | React.TouchEvent) => {
        setIsDrawing(true);
        const ctx = canvasRef.current?.getContext('2d');
        if (!ctx) return;
        const { x, y } = getPos(e);
        ctx.beginPath();
        ctx.moveTo(x, y);
    };

    const draw = (e: React.MouseEvent | React.TouchEvent) => {
        if (!isDrawing) return;
        e.preventDefault(); // Prevent scrolling
        const ctx = canvasRef.current?.getContext('2d');
        if (!ctx) return;
        const { x, y } = getPos(e);
        ctx.lineTo(x, y);
        ctx.stroke();
    };

    const stopDraw = () => {
        if (isDrawing && canvasRef.current) {
            onChange(canvasRef.current.toDataURL());
        }
        setIsDrawing(false);
    };

    const clear = () => {
        const ctx = canvasRef.current?.getContext('2d');
        if (ctx && canvasRef.current) {
            ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
            onChange('');
        }
    };

    return (
        <div className="border-2 border-gray-200 border-dashed rounded-xl bg-gray-50 overflow-hidden relative">
            <canvas 
                ref={canvasRef}
                width={500}
                height={200}
                className="w-full h-40 touch-none cursor-crosshair bg-white"
                onMouseDown={startDraw}
                onMouseMove={draw}
                onMouseUp={stopDraw}
                onMouseLeave={stopDraw}
                onTouchStart={startDraw}
                onTouchMove={draw}
                onTouchEnd={stopDraw}
            />
            {!value && !isDrawing && (
                <div className="absolute inset-0 flex items-center justify-center pointer-events-none text-gray-300 gap-2">
                    <PenTool size={20} /> 请在此区域手写签名
                </div>
            )}
            <button 
                type="button"
                onClick={clear}
                className="absolute top-2 right-2 p-1.5 bg-gray-100 hover:bg-red-50 text-gray-500 hover:text-red-500 rounded shadow-sm z-10"
                title="清除重写"
            >
                <RotateCcw size={14} />
            </button>
        </div>
    );
  };

  // --- Field Renderer ---
  const renderField = (field: FormField, idx: number) => {
    const error = errors[field.id];
    const isFocused = focusedField === field.id;

    return (
      <div 
         key={field.id} 
         id={field.id}
         className={`space-y-3 transition-all duration-300 ${isFocused ? 'transform scale-[1.01]' : ''}`}
      >
         <label className={`block text-sm font-bold transition-colors ${error ? 'text-red-500' : isFocused ? 'text-indigo-600' : 'text-gray-700'}`}>
            {idx + 1}. {field.label} {field.required && <span className="text-red-500">*</span>}
         </label>

         {/* TEXT Input */}
         {field.type === 'TEXT' && (
           <div className={`relative rounded-xl border-2 transition-all ${error ? 'border-red-100 bg-red-50' : isFocused ? 'border-indigo-500 bg-white shadow-md shadow-indigo-50' : 'border-gray-100 bg-gray-50 hover:border-gray-300'}`}>
             <input 
               type="text" 
               value={formData[field.id] || ''}
               onChange={e => handleChange(field.id, e.target.value)}
               onFocus={() => setFocusedField(field.id)}
               onBlur={() => setFocusedField(null)}
               placeholder={field.placeholder || '请输入...'}
               className="w-full px-4 py-3.5 bg-transparent border-none focus:ring-0 outline-none text-gray-800 placeholder-gray-400"
             />
           </div>
         )}

         {/* ADDRESS Input */}
         {field.type === 'ADDRESS' && (
           <div className={`relative rounded-xl border-2 transition-all ${error ? 'border-red-100 bg-red-50' : isFocused ? 'border-indigo-500 bg-white shadow-md shadow-indigo-50' : 'border-gray-100 bg-gray-50 hover:border-gray-300'}`}>
             <div className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">
               <MapPin size={20} />
             </div>
             <input 
               type="text" 
               value={formData[field.id] || ''}
               onChange={e => handleChange(field.id, e.target.value)}
               onFocus={() => setFocusedField(field.id)}
               onBlur={() => setFocusedField(null)}
               placeholder={field.placeholder || '请输入详细地址...'}
               className="w-full pl-12 pr-4 py-3.5 bg-transparent border-none focus:ring-0 outline-none text-gray-800 placeholder-gray-400"
             />
           </div>
         )}

         {/* NOTES / Textarea */}
         {field.type === 'NOTES' && (
           <div className={`relative rounded-xl border-2 transition-all ${error ? 'border-red-100 bg-red-50' : isFocused ? 'border-indigo-500 bg-white shadow-md shadow-indigo-50' : 'border-gray-100 bg-gray-50 hover:border-gray-300'}`}>
             <div className="absolute left-4 top-4 text-gray-400">
               <FileText size={20} />
             </div>
             <textarea 
               rows={4}
               value={formData[field.id] || ''}
               onChange={e => handleChange(field.id, e.target.value)}
               onFocus={() => setFocusedField(field.id)}
               onBlur={() => setFocusedField(null)}
               placeholder={field.placeholder || '请输入备注信息...'}
               className="w-full pl-12 pr-4 py-3.5 bg-transparent border-none focus:ring-0 outline-none text-gray-800 placeholder-gray-400 resize-none"
             />
           </div>
         )}

         {field.type === 'PHONE' && (
           <div className={`relative rounded-xl border-2 transition-all ${error ? 'border-red-100 bg-red-50' : isFocused ? 'border-indigo-500 bg-white shadow-md shadow-indigo-50' : 'border-gray-100 bg-gray-50 hover:border-gray-300'}`}>
             <input 
               type="tel" 
               value={formData[field.id] || ''}
               onChange={e => handleChange(field.id, e.target.value)}
               onFocus={() => setFocusedField(field.id)}
               onBlur={() => setFocusedField(null)}
               placeholder={field.placeholder || '请输入手机号码'}
               className="w-full px-4 py-3.5 bg-transparent border-none focus:ring-0 outline-none text-gray-800 placeholder-gray-400"
             />
           </div>
         )}

         {/* EMAIL Field */}
         {field.type === 'EMAIL' && (
           <div className={`relative rounded-xl border-2 transition-all ${error ? 'border-red-100 bg-red-50' : isFocused ? 'border-indigo-500 bg-white shadow-md shadow-indigo-50' : 'border-gray-100 bg-gray-50 hover:border-gray-300'}`}>
             <div className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">
               <Mail size={20} />
             </div>
             <input 
               type="email" 
               value={formData[field.id] || ''}
               onChange={e => handleChange(field.id, e.target.value)}
               onFocus={() => setFocusedField(field.id)}
               onBlur={() => setFocusedField(null)}
               placeholder={field.placeholder || 'example@domain.com'}
               className="w-full pl-12 pr-4 py-3.5 bg-transparent border-none focus:ring-0 outline-none text-gray-800 placeholder-gray-400"
             />
           </div>
         )}

         {field.type === 'NUMBER' && (
           <div className={`relative rounded-xl border-2 transition-all ${error ? 'border-red-100 bg-red-50' : isFocused ? 'border-indigo-500 bg-white shadow-md shadow-indigo-50' : 'border-gray-100 bg-gray-50 hover:border-gray-300'}`}>
             <input 
               type="number" 
               value={formData[field.id] || ''}
               onChange={e => handleChange(field.id, e.target.value)}
               onFocus={() => setFocusedField(field.id)}
               onBlur={() => setFocusedField(null)}
               placeholder={field.placeholder || '请输入数字...'}
               className="w-full px-4 py-3.5 bg-transparent border-none focus:ring-0 outline-none text-gray-800 placeholder-gray-400"
             />
           </div>
         )}

         {/* ID Card */}
         {field.type === 'ID_CARD' && (
           <div className={`relative rounded-xl border-2 transition-all ${error ? 'border-red-100 bg-red-50' : isFocused ? 'border-indigo-500 bg-white shadow-md shadow-indigo-50' : 'border-gray-100 bg-gray-50 hover:border-gray-300'}`}>
             <div className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">
               <UserSquare size={20} />
             </div>
             <input 
               type="text" 
               value={formData[field.id] || ''}
               onChange={e => handleChange(field.id, e.target.value)}
               onFocus={() => setFocusedField(field.id)}
               onBlur={() => setFocusedField(null)}
               placeholder={field.placeholder || '请输入身份证/护照/通行证号码'}
               className="w-full pl-12 pr-4 py-3.5 bg-transparent border-none focus:ring-0 outline-none text-gray-800 placeholder-gray-400"
             />
           </div>
         )}

         {/* Bank Card */}
         {field.type === 'BANK_CARD' && (
           <div className={`relative rounded-xl border-2 transition-all ${error ? 'border-red-100 bg-red-50' : isFocused ? 'border-indigo-500 bg-white shadow-md shadow-indigo-50' : 'border-gray-100 bg-gray-50 hover:border-gray-300'}`}>
             <div className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">
               <CreditCard size={20} />
             </div>
             <input 
               type="text" 
               value={formData[field.id] || ''}
               onChange={e => handleChange(field.id, e.target.value)}
               onFocus={() => setFocusedField(field.id)}
               onBlur={() => setFocusedField(null)}
               placeholder={field.placeholder || '请输入银行卡号'}
               className="w-full pl-12 pr-4 py-3.5 bg-transparent border-none focus:ring-0 outline-none text-gray-800 placeholder-gray-400"
             />
           </div>
         )}

         {field.type === 'DATE' && (
           <div className={`relative rounded-xl border-2 transition-all ${error ? 'border-red-100 bg-red-50' : isFocused ? 'border-indigo-500 bg-white shadow-md shadow-indigo-50' : 'border-gray-100 bg-gray-50 hover:border-gray-300'}`}>
             <input 
               type="date" 
               value={formData[field.id] || ''}
               onChange={e => handleChange(field.id, e.target.value)}
               onFocus={() => setFocusedField(field.id)}
               onBlur={() => setFocusedField(null)}
               className="w-full px-4 py-3.5 bg-transparent border-none focus:ring-0 outline-none text-gray-800 placeholder-gray-400"
             />
           </div>
         )}

         {(field.type === 'SELECT' || field.type === 'GENDER') && (
           <div className="flex flex-wrap gap-3 pt-1">
             {field.options?.map(opt => (
               <label 
                  key={opt} 
                  className={`flex-1 min-w-[120px] flex items-center justify-center gap-2 py-3 px-4 rounded-xl border-2 cursor-pointer transition-all text-sm font-medium
                    ${formData[field.id] === opt 
                      ? 'bg-indigo-600 border-indigo-600 text-white shadow-md shadow-indigo-200' 
                      : 'bg-white border-gray-100 text-gray-600 hover:border-indigo-200 hover:bg-gray-50'
                    }`}
               >
                  <input 
                    type="radio" 
                    name={field.id} 
                    value={opt} 
                    checked={formData[field.id] === opt}
                    onChange={() => handleChange(field.id, opt)}
                    className="hidden" 
                  />
                  {opt}
               </label>
             ))}
           </div>
         )}

         {field.type === 'SCHEDULE' && (
            <div className="pt-2 bg-indigo-50/50 p-4 rounded-xl border border-indigo-100">
               <p className="text-xs text-indigo-600 font-medium mb-3 flex items-center gap-1.5">
                 <Sparkles size={14} />
                 请点选您可以参加的具体时段（支持多选）
               </p>
               <div className="grid grid-cols-3 sm:grid-cols-4 gap-3">
                 {field.config?.dates?.map((date: string) => {
                    const status = formData[field.id]?.[date]; 
                    return (
                      <div key={date} className="flex flex-col gap-1.5 bg-white p-2 rounded-xl shadow-sm border border-gray-100">
                         <div className="text-center text-xs font-bold text-gray-500 mb-1">{date}</div>
                         <div className="grid grid-cols-1 gap-1.5">
                           {['全天', '上午', '下午'].map(opt => (
                             <button
                               key={opt}
                               type="button"
                               onClick={() => {
                                 const currentMap = formData[field.id] || {};
                                 if (currentMap[date] === opt) {
                                   const newMap = { ...currentMap };
                                   delete newMap[date];
                                   handleChange(field.id, newMap);
                                 } else {
                                   handleChange(field.id, { ...currentMap, [date]: opt });
                                 }
                               }}
                               className={`text-[10px] py-1.5 rounded-lg transition-all font-medium border ${
                                 status === opt 
                                   ? 'bg-indigo-500 text-white border-indigo-500 shadow-sm' 
                                   : 'bg-gray-50 text-gray-500 border-transparent hover:bg-gray-100'
                               }`}
                             >
                               {opt}
                             </button>
                           ))}
                         </div>
                      </div>
                    );
                 })}
               </div>
            </div>
         )}

         {/* Signature */}
         {field.type === 'SIGNATURE' && (
            <SignaturePad 
               value={formData[field.id]} 
               onChange={(val) => handleChange(field.id, val)} 
            />
         )}

         {error && (
            <div className="flex items-center gap-1.5 text-red-500 text-xs animate-pulse font-medium pl-1">
               <AlertCircle size={12} /> 此项为必填项
            </div>
         )}
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-[#F0F2F5] font-sans selection:bg-indigo-100 selection:text-indigo-800">
      {/* Top Banner */}
      <div className="h-56 bg-gradient-to-br from-indigo-600 to-violet-700 relative overflow-hidden">
         <div className="absolute inset-0 bg-[url('https://images.unsplash.com/photo-1557683316-973673baf926?q=80&w=2000&auto=format&fit=crop')] bg-cover bg-center mix-blend-overlay opacity-20"></div>
         <div className="absolute inset-0 bg-gradient-to-t from-black/40 to-transparent"></div>

         {/* Exit Button */}
         <div className="absolute top-4 left-4 z-10">
            <button 
               onClick={onCancel}
               className="bg-white/20 backdrop-blur-md text-white px-4 py-2 rounded-full text-sm font-bold hover:bg-white/30 transition-colors flex items-center gap-2"
            >
               <X size={16} /> 退出 (Exit)
            </button>
         </div>
      </div>

      <div className="max-w-2xl mx-auto -mt-24 px-4 pb-12 relative z-10">
        <form onSubmit={handleSubmit} className="bg-white rounded-2xl shadow-xl border border-white/50 backdrop-blur-sm overflow-hidden animate-fade-in">

          {/* Header Section */}
          <div className="p-8 md:p-10 border-b border-gray-100 bg-white">
             <h1 className="text-3xl font-extrabold text-gray-900 mb-4 tracking-tight">{form.title}</h1>
             <p className="text-gray-500 text-sm leading-relaxed whitespace-pre-wrap">
               {form.description}
             </p>
             <div className="flex items-center gap-4 mt-6 text-xs font-medium text-gray-400 bg-gray-50 p-3 rounded-lg border border-gray-100 w-fit">
                <span className="flex items-center gap-1.5"><Clock size={14} className="text-indigo-500" /> 预计填写 2 分钟</span>
                <span className="w-px h-3 bg-gray-300"></span>
                <span className="flex items-center gap-1.5"><Sparkles size={14} className="text-indigo-500" /> {form.fields.length} 个问题</span>
             </div>
          </div>

          {/* Form Fields */}
          <div className="p-6 md:p-10 space-y-10">
            {form.fields.map((field, idx) => renderField(field, idx))}
          </div>

          {/* Footer Actions */}
          <div className="p-8 bg-gray-50 border-t border-gray-100">
             <button 
               type="submit"
               disabled={loading}
               className="w-full bg-indigo-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-200 hover:shadow-indigo-300 hover:-translate-y-0.5 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2 active:scale-95 duration-200"
             >
               {loading ? '提交中...' : '提交表单'} <ChevronRight size={22} strokeWidth={3} />
             </button>
          </div>

        </form>
      </div>
    </div>
  );
};

