const generateMockAttendance = (staffList: Staff[]): AttendanceRecord[] => {
  const records: AttendanceRecord[] = [];
  const today = new Date();

  staffList.filter(s => s.status === 'ACTIVE').forEach(staff => {
    for (let i = 1; i < 4; i++) { // Generate fewer records for performance
      const date = new Date(today);
      date.setDate(today.getDate() - i);
      if (date.getDay() !== 0 && date.getDay() !== 6 && Math.random() > 0.1) {
        records.push({
           id: crypto.randomUUID(),
           staffId: staff.id,
           timestamp: new Date(date.setHours(8, 55 + Math.floor(Math.random()*15))).toISOString(),
           type: 'IN',
           status: Math.random() > 0.9 ? 'LATE' : 'NORMAL',
           photoUrl: `https://api.dicebear.com/7.x/avataaars/svg?seed=${staff.id}_${i}`
        });
      }
    }
  });
  return records;
};

const App: React.FC = () => {
  const [session, setSession] = useState<UserSession | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  // Data State
  const [staffList, setStaffList] = useState<Staff[]>([]);
  const [queueData, setQueueData] = useState<QueueTicket[]>([]);
  const [announcements, setAnnouncements] = useState<Announcement[]>([]);
  const [registrationList, setRegistrationList] = useState<RegistrationRecord[]>([]);
  const [onSiteRecords, setOnSiteRecords] = useState<RegistrationRecord[]>([]);
  const [attendanceRecords, setAttendanceRecords] = useState<AttendanceRecord[]>([]);
  const [groups, setGroups] = useState<Group[]>([]);
  const [forms, setForms] = useState<FormTemplate[]>([]);
  const [formSubmissions, setFormSubmissions] = useState<FormSubmission[]>([]);
  const [adminUsers, setAdminUsers] = useState<AdminUser[]>([]);

  // UI & Config State
  const [selectedFormId, setSelectedFormId] = useState<string | null>(null); 
  const [designerMode, setDesignerMode] = useState<'NONE' | 'EDIT' | 'ANALYTICS' | 'PREVIEW'>('NONE');
  const [systemDomain, setSystemDomain] = useState('https://workpulse.app');

  const [attendanceConfig, setAttendanceConfig] = useState<AttendanceConfig>({ startTime: '09:00', endTime: '18:00', overtimeStart: '19:00' });
  const [permissionSettings, setPermissionSettings] = useState<PermissionSettings>({
      allowLeaderExport: true,
      allowLeaderBroadcast: true,
      allowStaffViewTeam: false,
      showSensitiveInfo: true, 
      enableCheckIn: true,
  });
  const [loginConfig, setLoginConfig] = useState<LoginConfig>({ 
    title: 'STAFFTool', 
    subtitle: '', 
    imageUrl: '', 
    logoUrl: '',
    enableCandidateLogin: true 
  });
  const [registrationConfig, setRegistrationConfig] = useState<RegistrationConfig>({ masterPrefix: 'M', onSitePrefix: 'S' });

  // Initial Data Load
  useEffect(() => {
    const refreshData = async () => {
      setIsLoading(true);
      await new Promise(resolve => setTimeout(resolve, 500)); 

      const load = (key: string, def: any) => {
         const saved = localStorage.getItem(key);
         try { return saved ? JSON.parse(saved) : def; } catch { return def; }
      };

      setStaffList(load('staffList', []));
      setQueueData(load('queueData', []));
      setAnnouncements(load('announcements', MOCK_ANNOUNCEMENTS));
      setRegistrationList(load('registrationList', []));
      setOnSiteRecords(load('onSiteRecords', []));

      const savedAttendance = load('attendanceRecords', []);
      if (savedAttendance.length === 0) {
         setAttendanceRecords(generateMockAttendance(load('staffList', [])));
      } else {
         setAttendanceRecords(savedAttendance);
      }

      setGroups(load('groups', MOCK_GROUPS));
      setForms(load('forms', MOCK_FORMS));
      setFormSubmissions(load('formSubmissions', []));
      setAdminUsers(load('adminUsers', [{ username: 'admin', password: 'password' }]));
      setSystemDomain(load('systemDomain', 'https://workpulse.app'));

      setAttendanceConfig(load('attendanceConfig', { startTime: '09:00', endTime: '18:00', overtimeStart: '19:00' }));
      setPermissionSettings(load('permissionSettings', { allowLeaderExport: true, allowLeaderBroadcast: true, allowStaffViewTeam: false, showSensitiveInfo: true, enableCheckIn: true }));
      setLoginConfig(load('loginConfig', { title: 'STAFFTool', subtitle: '', imageUrl: '', logoUrl: '', enableCandidateLogin: true }));
      setRegistrationConfig(load('registrationConfig', { masterPrefix: 'M', onSitePrefix: 'S' }));

      setIsLoading(false);
    };

    refreshData();
  }, []);

  // --- Real-time Synchronization ---
  useEffect(() => {
    if (isLoading) return;

    const syncStateFromStorage = () => {
      const syncItem = (key: string, setter: React.Dispatch<React.SetStateAction<any>>) => {
        const saved = localStorage.getItem(key);
        if (saved) {
          try {
            const parsed = JSON.parse(saved);
            setter((prev: any) => {
              if (JSON.stringify(prev) !== saved) return parsed;
              return prev;
            });
          } catch(e) { console.error('Sync error', e); }
        }
      };

      // Sync All Critical Data
      syncItem('userSession', setSession); // Session Sync
      syncItem('queueData', setQueueData);
      syncItem('attendanceRecords', setAttendanceRecords);
      syncItem('registrationList', setRegistrationList);
      syncItem('onSiteRecords', setOnSiteRecords);
      syncItem('staffList', setStaffList);
      syncItem('groups', setGroups);
      syncItem('announcements', setAnnouncements);
      syncItem('forms', setForms);
      syncItem('formSubmissions', setFormSubmissions);
      syncItem('adminUsers', setAdminUsers);
      syncItem('attendanceConfig', setAttendanceConfig);
      syncItem('permissionSettings', setPermissionSettings);
      syncItem('loginConfig', setLoginConfig);
      syncItem('registrationConfig', setRegistrationConfig);
      syncItem('systemDomain', setSystemDomain);
    };

    window.addEventListener('storage', syncStateFromStorage);
    const intervalId = setInterval(syncStateFromStorage, 2000);

    return () => {
      window.removeEventListener('storage', syncStateFromStorage);
      clearInterval(intervalId);
    };
  }, [isLoading]);

  // --- Persistence ---
  const save = (key: string, data: any) => {
      if(!isLoading) localStorage.setItem(key, JSON.stringify(data));
  };

  useEffect(() => save('userSession', session), [session, isLoading]);
  useEffect(() => save('staffList', staffList), [staffList, isLoading]);
  useEffect(() => save('queueData', queueData), [queueData, isLoading]);
  useEffect(() => save('announcements', announcements), [announcements, isLoading]);
  useEffect(() => save('registrationList', registrationList), [registrationList, isLoading]);
  useEffect(() => save('onSiteRecords', onSiteRecords), [onSiteRecords, isLoading]); 
  useEffect(() => save('attendanceRecords', attendanceRecords), [attendanceRecords, isLoading]);
  useEffect(() => save('groups', groups), [groups, isLoading]);
  useEffect(() => save('forms', forms), [forms, isLoading]);
  useEffect(() => save('formSubmissions', formSubmissions), [formSubmissions, isLoading]);
  useEffect(() => save('systemDomain', systemDomain), [systemDomain, isLoading]);
  useEffect(() => save('attendanceConfig', attendanceConfig), [attendanceConfig, isLoading]);
  useEffect(() => save('permissionSettings', permissionSettings), [permissionSettings, isLoading]);
  useEffect(() => save('adminUsers', adminUsers), [adminUsers, isLoading]);
  useEffect(() => save('loginConfig', loginConfig), [loginConfig, isLoading]);
  useEffect(() => save('registrationConfig', registrationConfig), [registrationConfig, isLoading]);

  // --- Logic Handlers ---

  const handleLogin = (userId: string, role: 'ADMIN' | 'USER') => {
    if (role === 'ADMIN') {
      setSession({ userId, role });
      setActiveTab('dashboard');
    } else {
      let staff = staffList.find(s => s.id === userId);
      // Fallback to check candidates if not in main staff list
      if (!staff) {
        const candidate = registrationList.find(r => r.id === userId) || onSiteRecords.find(r => r.id === userId);
        if (candidate) {
          staff = {
            id: candidate.id,
            name: candidate.name,
            idCard: candidate.idCard || '',
            phone: candidate.phone,
            status: 'PENDING', 
            roles: [],
            avatar: '',
            joinDate: candidate.submissionTime,
            registrationNumber: candidate.registrationNumber
          };
        }
      }

      if (staff) {
        setSession({ userId, role, staff });
        // Redirect logic for candidates
        const isPendingAllocation = staff.roles.some(r => r.groupId === 'g_pending_allocation');
        const hasNoGroup = staff.roles.length === 0;
        const isNotActive = staff.status === 'PENDING' || staff.status === 'INTERVIEWED';

        if (isNotActive || isPendingAllocation || hasNoGroup) {
          setActiveTab('interviewee_dashboard');
        } else {
          setActiveTab('dashboard');
        }
      }
    };
  };

  const handleLogout = () => {
    setSession(null);
    setActiveTab('dashboard');
  };

  // Consolidated Punch Handler
  const handleStaffPunch = (type: 'IN' | 'OUT', photoUrl: string, status: AttendanceRecord['status'], timestamp: string) => {
    if (!session?.staff) return;
    const newRecord: AttendanceRecord = {
      id: crypto.randomUUID(),
      staffId: session.staff.id,
      timestamp: timestamp, 
      type,
      photoUrl,
      status
    };
    setAttendanceRecords(prev => [newRecord, ...prev]);
  };

  const handleUpdateOrAddRecord = (staffId: string, dateStr: string, type: 'IN' | 'OUT', timeStr: string) => {
    if (!timeStr) return;
    const targetTimestamp = new Date(`${dateStr}T${timeStr}`);
    const newStatus = calculateAttendanceStatus(type, targetTimestamp, attendanceConfig);

    let recordExists = false;
    const updatedRecords = attendanceRecords.map(rec => {
      if (rec.staffId === staffId && isSameDay(rec.timestamp, dateStr) && rec.type === type) {
        recordExists = true;
        return {
          ...rec,
          timestamp: targetTimestamp.toISOString(),
          status: newStatus,
          isManual: true,
          photoUrl: rec.photoUrl 
        };
      }
      return rec;
    });

    if (recordExists) {
      setAttendanceRecords(updatedRecords);
    } else {
      const newRecord: AttendanceRecord = {
        id: crypto.randomUUID(),
        staffId,
        timestamp: targetTimestamp.toISOString(),
        type,
        status: newStatus,
        isManual: true
      };
      setAttendanceRecords(prev => [newRecord, ...prev]);
    }
  };

  const handleQueueCheckIn = (staffId: string) => {
    if (queueData.some(t => t.staffId === staffId)) return;

    let person: Staff | RegistrationRecord | undefined = staffList.find(s => s.id === staffId);
    if (!person) person = registrationList.find(r => r.id === staffId);
    if (!person) person = onSiteRecords.find(r => r.id === staffId);

    if (!person) return; 

    // 1. Add to Queue
    const newTicket: QueueTicket = {
      id: crypto.randomUUID(),
      ticketNumber: `A-${String(queueData.length + 1).padStart(3, '0')}`,
      staffId: person.id,
      staffName: person.name,
      status: 'WAITING',
      checkInTime: new Date().toISOString()
    };
    setQueueData(prev => [...prev, newTicket]);

    // 2. Auto-generate Attendance Record
    const photoUrl = 'avatar' in person ? person.avatar : `https://api.dicebear.com/7.x/avataaars/svg?seed=${person.id}`;
    const now = new Date();
    const status = calculateAttendanceStatus('IN', now, attendanceConfig);

    const newRecord: AttendanceRecord = {
      id: crypto.randomUUID(),
      staffId: person.id,
      timestamp: now.toISOString(),
      type: 'IN',
      photoUrl: photoUrl,
      status: status
    };
    setAttendanceRecords(prev => [...prev, newRecord]);
  };

  // ... (Other handlers: updateTicketStatus, handleBatchAddStaffFromReg, etc. kept same)
  const updateTicketStatus = (ticketId: string, status: QueueTicket['status']) => {
    setQueueData(queueData.map(t => t.id === ticketId ? { ...t, status } : t));
  };

  const handleBatchAddStaffFromReg = (newStaffList: Staff[]) => {
    let count = 0;
    const updatedStaffList = [...staffList];
    newStaffList.forEach(newStaff => {
       const exists = updatedStaffList.some(s => 
          (s.idCard && s.idCard === newStaff.idCard) || 
          (s.phone && s.phone === newStaff.phone && s.name === newStaff.name)
       );
       if (!exists) {
         updatedStaffList.push(newStaff);
         count++;
       }
    });
    setStaffList(updatedStaffList);
    alert(`已成功将 ${count} 名人员导入。`);
  };

  // ... (CRUD handlers for Group, Admin, Form kept same)
  const handleAddGroup = (g: Group) => setGroups([...groups, g]);
  const handleUpdateGroup = (g: Group) => setGroups(groups.map(grp => grp.id === g.id ? g : grp));
  const handleDeleteGroup = (gid: string) => setGroups(groups.filter(g => g.id !== gid));
  const handleUpdateStaff = (s: Staff) => setStaffList(staffList.map(st => st.id === s.id ? s : st));
  const handleAddStaff = (s: Staff) => setStaffList([...staffList, s]);
  const handleAddAdmin = (u: AdminUser) => {
    if (adminUsers.some(a => a.username === u.username)) return false;
    setAdminUsers([...adminUsers, u]);
    return true;
  };
  const handleDeleteAdmin = (u: string) => {
    if (adminUsers.length > 1) setAdminUsers(adminUsers.filter(a => a.username !== u));
  };
  const handleUpdateAdminPassword = (u: string, p: string) => setAdminUsers(adminUsers.map(a => a.username === u ? {...a, password: p} : a));

  const handleCreateForm = () => {
    // Generate default schedule dates (next 3 days)
    const today = new Date();
    const dates = [];
    for(let i=0; i<3; i++) {
        const d = new Date(today);
        d.setDate(today.getDate() + i + 1);
        dates.push(`${d.getMonth()+1}.${d.getDate()}`);
    }

    const newForm: FormTemplate = {
      id: crypto.randomUUID(),
      shareToken: crypto.randomUUID().slice(0, 8),
      title: '未命名人员登记表',
      description: '请填写真实信息以便后续安排。',
      status: 'ACTIVE', 
      createdDate: new Date().toISOString().split('T')[0],
      submissionCount: 0,
      themeColor: 'blue',
      fields: [
        { id: crypto.randomUUID(), type: 'TEXT', label: '姓名', required: true, placeholder: '请输入真实姓名' },
        { id: crypto.randomUUID(), type: 'DATE', label: '出生日期', required: true },
        { id: crypto.randomUUID(), type: 'NUMBER', label: '年龄', required: true, placeholder: '请输入年龄' },
        { id: crypto.randomUUID(), type: 'GENDER', label: '性别', required: true, options: ['男', '女'] },
        { id: crypto.randomUUID(), type: 'PHONE', label: '手机号码', required: true, placeholder: '请输入11位手机号' },
        { id: crypto.randomUUID(), type: 'EMAIL', label: '邮箱', required: false, placeholder: '请输入邮箱地址' },
        { id: crypto.randomUUID(), type: 'ID_CARD', label: '身份证号码', required: true, placeholder: '请输入身份证号' },
        { id: crypto.randomUUID(), type: 'TEXT', label: '开户行', required: true, placeholder: '例如：招商银行' },
        { id: crypto.randomUUID(), type: 'TEXT', label: '支行信息', required: true, placeholder: '例如：广州天河支行' },
        { id: crypto.randomUUID(), type: 'BANK_CARD', label: '银行卡账号', required: true, placeholder: '请输入银行卡号' },
        { id: crypto.randomUUID(), type: 'NOTES', label: '工作经历', required: false, placeholder: '简述过往工作经验...' },
        { id: crypto.randomUUID(), type: 'SCHEDULE', label: '可参与时间段', required: true, config: { dates: dates } }
      ]
    };
    setForms([...forms, newForm]);
    setSelectedFormId(newForm.id);
    setDesignerMode('EDIT');
    setActiveTab('form_designer');
  };

  const handleNavigateToForm = (formId: string, mode: 'EDIT' | 'ANALYTICS' | 'PREVIEW') => {
    setSelectedFormId(formId);
    setDesignerMode(mode);
    setActiveTab('form_designer');
  };

  // Helper function to map form data to Registration Record
  const handlePublicFormSubmit = (submission: FormSubmission) => {
    const form = forms.find(f => f.id === submission.formId);
    if (!form) return;

    // Intelligent Field Mapping
    const mapField = (types: string[], labels: string[]) => {
      const field = form.fields.find(f => 
        types.includes(f.type) || labels.some(l => f.label.includes(l))
      );
      return field ? submission.data[field.id] : undefined;
    };

    const name = String(mapField(['TEXT'], ['姓名', '名字']) || '未知人员');
    const phone = String(mapField(['PHONE'], ['手机', '电话']) || '');
    const idCard = String(mapField(['ID_CARD'], ['身份证', '证件']) || '');
    const gender = String(mapField(['GENDER', 'SELECT'], ['性别']) || '');
    const age = String(mapField(['NUMBER'], ['年龄']) || '');
    const dob = String(mapField(['DATE'], ['出生', '生日']) || '');
    const notes = String(mapField(['NOTES'], ['备注', '经历']) || '');

    // Availability parsing
    const scheduleField = form.fields.find(f => f.type === 'SCHEDULE');
    let availabilityStr = '{}';
    if (scheduleField) {
       const rawAvail = submission.data[scheduleField.id];
       if (rawAvail && typeof rawAvail === 'object') {
          const cleanAvail: Record<string, string> = {};
          Object.entries(rawAvail).forEach(([k, v]) => {
             if (v === '全天') cleanAvail[k] = 'FULL';
             else if (v === '上午') cleanAvail[k] = 'AM';
             else if (v === '下午') cleanAvail[k] = 'PM';
          });
          availabilityStr = JSON.stringify(cleanAvail);
       }
    }

    const newRecord: RegistrationRecord = {
      id: submission.id, // Reuse ID for consistency
      registrationNumber: `${registrationConfig.onSitePrefix}${String(onSiteRecords.length + 1).padStart(5, '0')}`,
      name,
      phone,
      idCard,
      gender,
      age,
      dob,
      submissionTime: submission.submittedAt,
      notes,
      availability: availabilityStr,
      managementNotes: '现场扫码报名',
      isTalent: false
    };

    // 1. Sync to OnSite Records (Backend Sync)
    setOnSiteRecords(prev => [...prev, newRecord]);

    // 2. Also save the raw submission
    setFormSubmissions(prev => [...prev, submission]);

    // 3. Update Submission Count on Form
    setForms(prev => prev.map(f => f.id === form.id ? { ...f, submissionCount: f.submissionCount + 1 } : f));

    // 4. Redirect to Login (Candidate View)
    setActiveTab('login');
    alert(`报名成功！请使用姓名和手机号登录系统以获取入场二维码。\n\n姓名：${name}\n手机：${phone}`);
  };

  // View Routing
  const renderContent = () => {
    if (isLoading) return <div className="flex h-full items-center justify-center"><div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600"></div></div>;

    if (activeTab === 'interviewee_dashboard' && session?.staff) {
      const myTicket = queueData.find(t => t.staffId === session.staff?.id);
      return <IntervieweeDashboard staff={session.staff} myTicket={myTicket} ticketsAhead={0} onLogout={handleLogout} />;
    }

    if (activeTab === 'form_designer' && selectedFormId) {
       const form = forms.find(f => f.id === selectedFormId);
       if (!form) return <div>Form not found</div>;
       if (designerMode === 'EDIT') return <FormDesigner form={form} onSave={(u) => setForms(forms.map(f => f.id === u.id ? u : f))} onPublish={() => setDesignerMode('PREVIEW')} onBack={() => setActiveTab('form_manager')} />;
       if (designerMode === 'ANALYTICS') return <FormAnalytics form={form} submissions={formSubmissions.filter(s => s.formId === form.id)} onDeleteSubmission={(sid) => setFormSubmissions(formSubmissions.filter(s => s.id !== sid))} onBack={() => setActiveTab('form_manager')} onShare={() => setDesignerMode('PREVIEW')} />;
       if (designerMode === 'PREVIEW') return <FormShareDashboard form={form} onBack={() => setDesignerMode('ANALYTICS')} onPreview={() => setActiveTab('public_view_simulation')} customDomain={systemDomain} />; 
    }

    // Public View Simulation Logic
    if (activeTab === 'public_view_simulation' && selectedFormId) {
       const form = forms.find(f => f.id === selectedFormId);
       if (form) {
          return <PublicDynamicForm 
             form={form} 
             onSubmit={handlePublicFormSubmit} 
             onCancel={() => { 
                if (session) { 
                   if (designerMode === 'PREVIEW') setActiveTab('form_designer'); 
                   else setActiveTab('form_manager'); 
                } else {
                   setActiveTab('login'); 
                }
             }} 
          />;
       }
    }

    switch (activeTab) {
      case 'dashboard':
        if (session?.role === 'USER' && session?.staff) {
          const userGroup = groups.find(g => session.staff?.roles.some(r => r.groupId === g.id));
          const myRecords = attendanceRecords.filter(r => r.staffId === session.staff?.id).sort((a,b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
          const status = myRecords[0]?.type === 'IN' ? AttendanceStatus.CLOCKED_IN : AttendanceStatus.CLOCKED_OUT;
          return <StaffDashboard 
              currentUser={session.staff}
              group={userGroup}
              leaders={staffList.filter(s => s.roles.some(r => r.groupId === userGroup?.id && r.isLeader))}
              staffList={staffList}
              announcements={announcements.filter(a => !a.targetGroupId || a.targetGroupId === userGroup?.id)}
              attendanceStatus={status}
              attendanceHistory={myRecords.filter(r => isSameDay(r.timestamp, new Date().toISOString()))}
              attendanceConfig={attendanceConfig}
              onClockIn={(p, s, t) => handleStaffPunch('IN', p, s, t)}
              onClockOut={(p, s, t) => handleStaffPunch('OUT', p, s, t)}
            />;
        }
        return <Dashboard 
          attendanceRecords={attendanceRecords}
          queueData={queueData}
          announcements={announcements}
          isAdmin={session?.role === 'ADMIN'}
          staffList={staffList}
          groups={groups}
          currentUser={session?.staff}
        />;

      case 'reports':
        let visibleGroups = groups;
        if (session?.role === 'USER' && session.staff) {
           const leaderGroupIds = session.staff.roles.filter(r => r.isLeader).map(r => r.groupId);
           visibleGroups = groups.filter(g => leaderGroupIds.includes(g.id));
        }
        return <AttendanceReports 
          staffList={staffList} 
          groups={visibleGroups} 
          allRecords={attendanceRecords}
          session={session}
          permissionSettings={permissionSettings}
          attendanceConfig={attendanceConfig}
          onUpdateOrAddRecord={handleUpdateOrAddRecord}
        />;

      case 'checkin_system':
        return <CheckInSystem 
          queue={queueData}
          registrationList={registrationList}
          onSiteRecords={onSiteRecords}
          staffList={staffList}
          onCheckIn={handleQueueCheckIn}
          onClearQueue={() => setQueueData([])}
          onUpdateTicketStatus={updateTicketStatus}
        />;

      case 'training_checkin': 
        return <TrainingCheckinManager 
          queue={queueData}
          registrationList={registrationList}
          onSiteRecords={onSiteRecords} 
          onUpdateOnSiteRecords={setOnSiteRecords}
          staffList={staffList}
          forms={forms}
          formSubmissions={formSubmissions}
          onUpdateRegistration={setRegistrationList}
          onBatchAddStaff={handleBatchAddStaffFromReg}
          onManageForm={handleNavigateToForm}
          permissionSettings={permissionSettings}
          session={session}
          registrationConfig={registrationConfig}
        />;

      case 'form_manager':
        return <FormManager 
          forms={forms} 
          onCreateForm={handleCreateForm} 
          onDeleteForm={(id) => { 
             if(window.confirm('确定要删除此表单吗？操作无法恢复。')) { 
                setForms(forms.filter(f => f.id !== id)); 
                setFormSubmissions(formSubmissions.filter(s => s.formId !== id)); 
             }
          }} 
          onSelectForm={(id, mode) => { setSelectedFormId(id); if (mode === 'SIMULATE') setActiveTab('public_view_simulation'); else { setDesignerMode(mode); setActiveTab('form_designer'); } }} 
          onToggleStatus={(id, s) => setForms(forms.map(f => f.id === id ? { ...f, status: s } : f))}
        />;
      case 'outsourced':
        return <OutsourcedManager 
          permissionSettings={permissionSettings}
          staffList={staffList} 
          groups={groups} 
          registrationList={registrationList} 
          onSiteRecords={onSiteRecords} 
          onUpdateStaff={handleUpdateStaff} 
          onAddStaff={handleAddStaff} 
          onBatchAddStaff={handleBatchAddStaffFromReg}
          onAddGroup={handleAddGroup} 
          onUpdateGroup={handleUpdateGroup} 
          onDeleteGroup={handleDeleteGroup} 
        />;
      case 'announcements':
        return <AnnouncementManager currentUserRole={session?.role || 'USER'} currentUserGroups={session?.staff?.roles || []} announcements={announcements} onAddAnnouncement={(a) => setAnnouncements([a, ...announcements])} onDeleteAnnouncement={(id) => setAnnouncements(announcements.filter(a => a.id !== id))} currentUserName={session?.staff?.name || '管理员'} />;
      case 'settings':
        return <SystemSettings 
          onSave={(s) => { setSystemDomain(s.domain); setAttendanceConfig(s.attendance); setPermissionSettings(s.permissions); setLoginConfig(s.loginConfig); setRegistrationConfig(s.registrationConfig); }} 
          initialDomain={systemDomain} 
          initialAttendanceConfig={attendanceConfig} 
          initialPermissionSettings={permissionSettings}
          initialLoginConfig={loginConfig}
          initialRegistrationConfig={registrationConfig}
          adminUsers={adminUsers}
          onAddAdmin={handleAddAdmin}
          onDeleteAdmin={handleDeleteAdmin}
          onUpdateAdminPassword={handleUpdateAdminPassword}
        />;
      default: return null;
    }
  };

  if (!session) return <Login staffList={staffList} registrationList={registrationList} onLogin={handleLogin} adminUsers={adminUsers} loginConfig={loginConfig} />;

  const isLeader = session.role === 'USER' && session.staff?.roles.some(r => r.isLeader);
  const canScanCheckIn = permissionSettings.enableCheckIn && session.role === 'USER' && session.staff?.roles.some(r => r.groupId === 'g_out' || r.groupId === 'g_service_center');
  const isFullScreen = (activeTab === 'form_designer' && designerMode === 'EDIT') || activeTab === 'interviewee_dashboard' || activeTab === 'public_view_simulation';

  return (
    <div className="flex min-h-screen bg-[#F1F5F9] text-gray-900 font-sans selection:bg-indigo-100 selection:text-indigo-600">
      {!isFullScreen && (
        <aside className={`fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 text-white transition-transform duration-300 ease-in-out hidden lg:flex flex-col shadow-2xl`}>
          <div className="flex items-center justify-start p-6 border-b border-slate-800/50">
             <h1 className="text-xl font-bold tracking-tight text-white">Staff-system</h1>
          </div>
          <nav className="flex-1 overflow-y-auto py-6 px-4 space-y-1 custom-scrollbar">
            {session.role === 'ADMIN' ? (
              <>
                 <div className="mb-6">
                    <p className="px-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-3">管理中心</p>
                    <button onClick={() => setActiveTab('dashboard')} className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl transition-all duration-200 group ${activeTab === 'dashboard' ? 'bg-gradient-to-r from-indigo-600 to-violet-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-white/5 hover:text-white'}`}>
                      <LayoutDashboard size={20} /> <span className="font-medium text-sm">工作台</span>
                    </button>
                 </div>
                 <div className="mb-6">
                     <p className="px-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-3">人员与事务</p>
                     <button onClick={() => setActiveTab('training_checkin')} className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl transition-all duration-200 mb-1 group ${activeTab === 'training_checkin' ? 'bg-gradient-to-r from-indigo-600 to-violet-600 text-white' : 'text-slate-400 hover:bg-white/5'}`}><ClipboardCheck size={20} /> <span>报名数据</span></button>
                     <button onClick={() => setActiveTab('checkin_system')} className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl transition-all duration-200 mb-1 group ${activeTab === 'checkin_system' ? 'bg-gradient-to-r from-indigo-600 to-violet-600 text-white' : 'text-slate-400 hover:bg-white/5'}`}><ScanLine size={20} /> <span>现场签到</span></button>
                     <button onClick={() => setActiveTab('outsourced')} className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl transition-all duration-200 mb-1 group ${activeTab === 'outsourced' ? 'bg-gradient-to-r from-indigo-600 to-violet-600 text-white' : 'text-slate-400 hover:bg-white/5'}`}><Briefcase size={20} /> <span>分组与编外</span></button>
                     <button onClick={() => setActiveTab('form_manager')} className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl transition-all duration-200 mb-1 group ${activeTab === 'form_manager' || activeTab === 'form_designer' ? 'bg-gradient-to-r from-indigo-600 to-violet-600 text-white' : 'text-slate-400 hover:bg-white/5'}`}><FileText size={20} /> <span>表单中心</span></button>
                 </div>
                 <div className="mb-6">
                    <p className="px-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-3">系统管理</p>
                    <button onClick={() => setActiveTab('announcements')} className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl transition-all duration-200 mb-1 group ${activeTab === 'announcements' ? 'bg-gradient-to-r from-indigo-600 to-violet-600 text-white' : 'text-slate-400 hover:bg-white/5'}`}><Megaphone size={20} /> <span>公告通知</span></button>
                    <button onClick={() => setActiveTab('reports')} className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl transition-all duration-200 mb-1 group ${activeTab === 'reports' ? 'bg-gradient-to-r from-indigo-600 to-violet-600 text-white' : 'text-slate-400 hover:bg-white/5'}`}><BarChart3 size={20} /> <span>考勤报表</span></button>
                    <button onClick={() => setActiveTab('settings')} className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl transition-all duration-200 mb-1 group ${activeTab === 'settings' ? 'bg-gradient-to-r from-indigo-600 to-violet-600 text-white' : 'text-slate-400 hover:bg-white/5'}`}><Settings size={20} /> <span>系统设置</span></button>
                 </div>
              </>
            ) : (
              <>
                <button onClick={() => setActiveTab('dashboard')} className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl transition-all duration-200 group ${activeTab === 'dashboard' ? 'bg-gradient-to-r from-indigo-600 to-violet-600 text-white' : 'text-slate-400 hover:bg-white/5'}`}><Home size={20} /> <span>我的主页</span></button>
                {canScanCheckIn && <button onClick={() => setActiveTab('checkin_system')} className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl transition-all duration-200 mt-1 group ${activeTab === 'checkin_system' ? 'bg-gradient-to-r from-indigo-600 to-violet-600 text-white' : 'text-slate-400 hover:bg-white/5'}`}><ScanLine size={20} /> <span>现场签到</span></button>}
                {isLeader && (
                   <>
                     <p className="px-4 mt-6 text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-3">组长管理</p>
                     <button onClick={() => setActiveTab('reports')} className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl transition-all duration-200 mb-1 group ${activeTab === 'reports' ? 'bg-gradient-to-r from-indigo-600 to-violet-600 text-white' : 'text-slate-400 hover:bg-white/5'}`}><BarChart3 size={20} /> <span>考勤记录</span></button>
                     {permissionSettings.allowLeaderBroadcast && <button onClick={() => setActiveTab('announcements')} className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl transition-all duration-200 mb-1 group ${activeTab === 'announcements' ? 'bg-gradient-to-r from-indigo-600 to-violet-600 text-white' : 'text-slate-400 hover:bg-white/5'}`}><Megaphone size={20} /> <span>发布公告</span></button>}
                   </>
                )}
              </>
            )}
          </nav>
          <div className="p-4 border-t border-slate-800/50">
             <div className="flex items-center justify-between gap-3 px-2 bg-slate-800/50 p-3 rounded-2xl border border-slate-700/50">
               <div className="min-w-0">
                  <p className="text-sm font-bold text-white truncate">{session.staff?.name || '管理员'}</p>
                  <p className="text-[10px] text-slate-400 truncate">{session.role === 'ADMIN' ? 'Super Admin' : (session.staff?.roles[0]?.groupName || 'Staff')}</p>
               </div>
               <button onClick={handleLogout} className="text-slate-400 hover:text-white transition-colors bg-white/5 p-2 rounded-xl hover:bg-red-500/20 hover:text-red-400"><LogOut size={16} /></button>
             </div>
          </div>
        </aside>
      )}
      <main className={`flex-1 flex flex-col min-h-screen transition-all duration-300 ${!isFullScreen ? 'lg:ml-64' : ''}`}>
        {!isFullScreen && (
          <header className="bg-white/80 backdrop-blur-md border-b border-gray-100 p-4 flex justify-between items-center lg:hidden sticky top-0 z-40 shadow-sm">
             <div className="flex items-center gap-3">
                <button onClick={() => setSidebarOpen(true)} className="text-gray-600 p-1 hover:bg-gray-100 rounded-lg"><Menu size={24} /></button>
                <h1 className="font-bold text-gray-800 text-lg">Staff-system</h1>
             </div>
          </header>
        )}
        {sidebarOpen && !isFullScreen && (
          <div className="fixed inset-0 bg-black/50 z-50 lg:hidden" onClick={() => setSidebarOpen(false)}>
            <div className="bg-slate-900 w-64 h-full shadow-2xl p-4 flex flex-col" onClick={e => e.stopPropagation()}>
               <div className="flex justify-between items-center mb-8 px-2"><span className="text-white font-bold text-xl">Staff-system</span><button onClick={() => setSidebarOpen(false)} className="text-slate-400 hover:text-white"><X size={24} /></button></div>
               <nav className="flex-1 space-y-2 overflow-y-auto">
                 <button onClick={() => { setActiveTab('dashboard'); setSidebarOpen(false); }} className="w-full text-left px-4 py-3 rounded-xl text-slate-400 hover:bg-slate-800 hover:text-white font-medium text-sm">工作台</button>
                 {session.role === 'ADMIN' && (
                   <>
                      <button onClick={() => { setActiveTab('training_checkin'); setSidebarOpen(false); }} className="w-full text-left px-4 py-3 rounded-xl text-slate-400 hover:bg-slate-800 hover:text-white font-medium text-sm">报名数据</button>
                      <button onClick={() => { setActiveTab('checkin_system'); setSidebarOpen(false); }} className="w-full text-left px-4 py-3 rounded-xl text-slate-400 hover:bg-slate-800 hover:text-white font-medium text-sm">现场签到</button>
                      <button onClick={() => { setActiveTab('outsourced'); setSidebarOpen(false); }} className="w-full text-left px-4 py-3 rounded-xl text-slate-400 hover:bg-slate-800 hover:text-white font-medium text-sm">分组与编外</button>
                      <button onClick={() => { setActiveTab('form_manager'); setSidebarOpen(false); }} className="w-full text-left px-4 py-3 rounded-xl text-slate-400 hover:bg-slate-800 hover:text-white font-medium text-sm">表单中心</button>
                      <button onClick={() => { setActiveTab('announcements'); setSidebarOpen(false); }} className="w-full text-left px-4 py-3 rounded-xl text-slate-400 hover:bg-slate-800 hover:text-white font-medium text-sm">公告通知</button>
                      <button onClick={() => { setActiveTab('reports'); setSidebarOpen(false); }} className="w-full text-left px-4 py-3 rounded-xl text-slate-400 hover:bg-slate-800 hover:text-white font-medium text-sm">考勤报表</button>
                      <button onClick={() => { setActiveTab('settings'); setSidebarOpen(false); }} className="w-full text-left px-4 py-3 rounded-xl text-slate-400 hover:bg-slate-800 hover:text-white font-medium text-sm">系统设置</button>
                   </>
                 )}
               </nav>
            </div>
          </div>
        )}
        <div className="flex-1 p-6 md:p-8 overflow-y-auto bg-[#F1F5F9]">{renderContent()}</div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import { QueueTicket, RegistrationRecord, Staff } from '../types';
import { 
  ScanLine, 
  Camera, 
  X, 
  Search, 
  CheckCircle2, 
  AlertTriangle, 
  UserX, 
  UserCheck, 
  Clock, 
  ListFilter,
  Trash2,
  Phone,
  User,
  Zap,
  SwitchCamera,
  History
} from 'lucide-react';
import jsQR from 'jsqr';

interface QueueManagerProps {
  pendingStaff: Staff[]; 
  queue: QueueTicket[];
  registrationList: RegistrationRecord[]; 
  onCheckIn: (staffId: string) => void;
  onUpdateTicketStatus: (ticketId: string, status: QueueTicket['status']) => void;
  onBulkCheckIn?: (staffIds: string[]) => void;
  onClearQueue?: () => void;
}

interface ScanResult {
  status: 'SUCCESS' | 'ERROR' | 'WARNING';
  title: string;
  message: string;
  record?: RegistrationRecord | null;
}

const QueueManager: React.FC<QueueManagerProps> = ({ 
  queue, 
  registrationList, 
  onCheckIn, 
  onClearQueue 
}) => {
  // UI State
  const [activeTab, setActiveTab] = useState<'PENDING' | 'CHECKED'>('PENDING');
  const [searchTerm, setSearchTerm] = useState('');

  // Scanner State
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [cameraError, setCameraError] = useState('');
  const [scanResult, setScanResult] = useState<ScanResult | null>(null);
  const [lastScanned, setLastScanned] = useState<ScanResult | null>(null);

  // Camera Device Management
  const [currentDeviceId, setCurrentDeviceId] = useState<string>('');
  const [videoDevices, setVideoDevices] = useState<MediaDeviceInfo[]>([]);

  // Refs
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>(0);

  // --- Data Logic ---
  const checkedInIds = useMemo(() => new Set(queue.map(t => t.staffId)), [queue]);

  const pendingList = useMemo(() => {
    return registrationList.filter(r => !checkedInIds.has(r.id));
  }, [registrationList, checkedInIds]);

  const displayPending = useMemo(() => {
    const term = searchTerm.toLowerCase();
    return pendingList.filter(r => 
      r.name.toLowerCase().includes(term) || 
      (r.phone && r.phone.includes(term)) ||
      r.registrationNumber.includes(term)
    );
  }, [pendingList, searchTerm]);

  const displayChecked = useMemo(() => {
    const term = searchTerm.toLowerCase();
    return [...queue].reverse().filter(t => 
      t.staffName.toLowerCase().includes(term) || 
      t.ticketNumber.toLowerCase().includes(term)
    );
  }, [queue, searchTerm]);

  // --- Audio Feedback ---
  const playSound = (type: 'success' | 'error') => {
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      if (!AudioContext) return;
      const ctx = new AudioContext();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);

      if (type === 'success') {
        osc.type = 'sine';
        osc.frequency.setValueAtTime(880, ctx.currentTime);
        osc.frequency.exponentialRampToValueAtTime(1760, ctx.currentTime + 0.1);
        gain.gain.setValueAtTime(0.1, ctx.currentTime);
        gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.1);
        osc.start();
        osc.stop(ctx.currentTime + 0.15);
      } else {
        osc.type = 'sawtooth';
        osc.frequency.setValueAtTime(150, ctx.currentTime);
        osc.frequency.linearRampToValueAtTime(100, ctx.currentTime + 0.3);
        gain.gain.setValueAtTime(0.1, ctx.currentTime);
        gain.gain.linearRampToValueAtTime(0, ctx.currentTime + 0.3);
        osc.start();
        osc.stop(ctx.currentTime + 0.3);
      }
    } catch (e) { console.error(e); }
  };

  // --- Scan Handler ---
  const handleScanCode = useCallback((code: string) => {
    let targetId = code.trim();
    try {
      const parsed = JSON.parse(targetId);
      if (parsed.uid) targetId = parsed.uid;
    } catch (e) {}

    const record = registrationList.find(r => r.id === targetId || r.phone === targetId);

    if (!record) {
      playSound('error');
      const res: ScanResult = { status: 'ERROR', title: '无效二维码', message: '系统未找到该人员信息', record: null };
      setScanResult(res);
      setLastScanned(res);
      setTimeout(() => setScanResult(null), 2000);
      return;
    }

    if (checkedInIds.has(record.id)) {
      playSound('error');
      const res: ScanResult = { 
        status: 'WARNING', 
        title: '重复签到', 
        message: `${record.name} 已于 ${new Date().toLocaleTimeString()} 完成签到`,
        record 
      };
      setScanResult(res);
      setLastScanned(res);
      setTimeout(() => setScanResult(null), 2000);
      return;
    }

    playSound('success');
    onCheckIn(record.id);
    const res: ScanResult = {
      status: 'SUCCESS',
      title: '签到成功',
      message: '欢迎参加',
      record
    };
    setScanResult(res);
    setLastScanned(res);
    setTimeout(() => setScanResult(null), 1500);

  }, [registrationList, checkedInIds, onCheckIn]);

  // --- Camera Logic ---
  const tick = useCallback(() => {
    if (scanResult) {
      // Pause scanning while showing result
      requestRef.current = requestAnimationFrame(tick);
      return;
    }
    if (videoRef.current && videoRef.current.readyState === videoRef.current.HAVE_ENOUGH_DATA) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      if (canvas) {
        canvas.height = video.videoHeight;
        canvas.width = video.videoWidth;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
          const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
          const code = jsQR(imageData.data, imageData.width, imageData.height, { inversionAttempts: "dontInvert" });

          if (code && code.data) {
             handleScanCode(code.data);
          }
        }
      }
    }
    requestRef.current = requestAnimationFrame(tick);
  }, [handleScanCode, scanResult]);

  // Get available cameras
  useEffect(() => {
    const getDevices = async () => {
      try {
        const devices = await navigator.mediaDevices.enumerateDevices();
        const videoInputs = devices.filter(device => device.kind === 'videoinput');
        setVideoDevices(videoInputs);
        if (videoInputs.length > 0 && !currentDeviceId) {
           // Default to back camera if available, else first
           const backCam = videoInputs.find(d => d.label.toLowerCase().includes('back') || d.label.toLowerCase().includes('rear'));
           setCurrentDeviceId(backCam ? backCam.deviceId : videoInputs[0].deviceId);
        }
      } catch(e) {
        console.error("Error listing devices", e);
      }
    };
    getDevices();
  }, []);

  // START CAMERA EFFECT (Fix for "Camera not showing preview")
  useEffect(() => {
    let activeStream: MediaStream | null = null;

    const initCamera = async () => {
      if (!isCameraActive) return;

      setCameraError('');
      if (requestRef.current) cancelAnimationFrame(requestRef.current);

      try {
        const constraints = { 
          video: currentDeviceId ? { deviceId: { exact: currentDeviceId } } : { facingMode: "environment" } 
        };

        const stream = await navigator.mediaDevices.getUserMedia(constraints);
        activeStream = stream;

        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          videoRef.current.setAttribute("playsinline", "true");
          // Wait for video to be ready to play
          videoRef.current.onloadedmetadata = async () => {
             try {
                await videoRef.current?.play();
                requestRef.current = requestAnimationFrame(tick);
             } catch (e) {
                console.error("Play failed", e);
             }
          };
        }
      } catch (err) {
        console.error(err);
        setCameraError('无法访问摄像头，请检查权限。');
        setIsCameraActive(false);
      }
    };

    if (isCameraActive) {
       initCamera();
    } else {
       // Cleanup if inactive
       if (requestRef.current) cancelAnimationFrame(requestRef.current);
    }

    return () => {
      if (activeStream) {
        activeStream.getTracks().forEach(track => track.stop());
      }
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [isCameraActive, currentDeviceId, tick]);

  const switchCamera = () => {
    if (videoDevices.length < 2) return;
    const currentIndex = videoDevices.findIndex(d => d.deviceId === currentDeviceId);
    const nextIndex = (currentIndex + 1) % videoDevices.length;
    const nextDevice = videoDevices[nextIndex];
    setCurrentDeviceId(nextDevice.deviceId);
    // State change of currentDeviceId will trigger the effect above to restart camera
  };

  // --- Manual Action ---
  const handleManualCheckIn = (record: RegistrationRecord) => {
    if (checkedInIds.has(record.id)) return;
    handleScanCode(record.id); // Re-use logic for consistent feedback
  };

  const handleResetData = (e: React.MouseEvent) => {
    e.stopPropagation();
    if(window.confirm('确定清空所有签到记录吗？此操作无法撤销。')) {
        if (onClearQueue) onClearQueue();
    }
  };

  return (
    <div className="flex flex-col lg:flex-row h-full gap-6">

      {/* LEFT COLUMN: Camera Scanner & Stats */}
      <div className="lg:w-96 flex flex-col gap-4 shrink-0">

         {/* 1. Camera Card */}
         <div className="bg-black rounded-[2rem] overflow-hidden shadow-2xl relative aspect-[3/4] flex flex-col items-center justify-center group ring-8 ring-gray-100">

            {/* Top Bar inside Camera */}
            <div className="absolute top-0 left-0 right-0 p-4 z-20 flex justify-between items-center bg-gradient-to-b from-black/60 to-transparent">
               <span className="text-white/80 text-xs font-mono flex items-center gap-2">
                  <div className={`w-2 h-2 rounded-full ${isCameraActive ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`}></div>
                  {isCameraActive ? 'LIVE FEED' : 'OFFLINE'}
               </span>
               {videoDevices.length > 1 && isCameraActive && (
                  <button onClick={switchCamera} className="p-2 bg-white/20 hover:bg-white/30 rounded-full text-white backdrop-blur-md transition-colors">
                     <SwitchCamera size={16} />
                  </button>
               )}
            </div>

            {/* Video Feed */}
            {!isCameraActive ? (
