import React from 'react';
import { FormTemplate } from '../types';
import { 
  Plus, 
  FileText, 
  BarChart2, 
  Edit3, 
  Share2, 
  Trash2,
  LayoutGrid,
  Clock
} from 'lucide-react';

interface FormManagerProps {
  forms: FormTemplate[];
  onCreateForm: () => void;
  onSelectForm: (formId: string, action: 'EDIT' | 'ANALYTICS' | 'PREVIEW' | 'SIMULATE') => void;
  onDeleteForm: (formId: string) => void;
  onToggleStatus?: (formId: string, newStatus: 'ACTIVE' | 'CLOSED') => void;
}

const FormManager: React.FC<FormManagerProps> = ({ forms, onCreateForm, onSelectForm, onDeleteForm, onToggleStatus }) => {

  const getThemeGradient = (color: string) => {
    if (color === 'purple') return 'bg-gradient-to-br from-violet-500 to-fuchsia-600';
    if (color === 'green') return 'bg-gradient-to-br from-emerald-400 to-teal-600';
    if (color === 'orange') return 'bg-gradient-to-br from-amber-400 to-orange-600';
    return 'bg-gradient-to-br from-blue-500 to-indigo-600'; // Default blue
  };

  const handleDeleteClick = (e: React.MouseEvent, formId: string) => {
    e.stopPropagation();
    // Using window.confirm directly inside the component ensures the event loop isn't blocked upstream
    if (window.confirm('确定要删除此表单吗？删除后所有相关数据也将被移除，且无法恢复。')) {
        onDeleteForm(formId);
    }
  };

  return (
    <div className="space-y-6 animate-fade-in pb-24">
      {/* Header */}
      <div className="flex justify-between items-center bg-white p-4 rounded-xl border border-gray-200 shadow-sm">
        <h2 className="text-lg font-bold text-gray-800 flex items-center gap-2">
           <LayoutGrid size={20} className="text-indigo-600" /> 
           <span>所有表单</span>
           <span className="text-xs font-normal text-gray-400 bg-gray-100 px-2 py-0.5 rounded-full">{forms.length}</span>
        </h2>
        <button 
          onClick={onCreateForm}
          className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-bold shadow-sm hover:bg-indigo-700 transition-all flex items-center gap-2"
        >
          <Plus size={16} strokeWidth={3} /> 新建表单
        </button>
      </div>

      {/* Forms Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
        {forms.map(form => (
          <div key={form.id} className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden flex flex-col hover:shadow-xl hover:border-indigo-100 hover:-translate-y-1 transition-all duration-300 group relative">

             {/* Card Header (Colored) */}
             <div className={`h-28 ${getThemeGradient(form.themeColor)} relative p-4 flex flex-col justify-between overflow-hidden`}>
                {/* Decorative Pattern */}
                <div className="absolute inset-0 opacity-10 bg-[radial-gradient(circle_at_1px_1px,rgba(255,255,255,0.4)_1px,transparent_0)] bg-[length:16px_16px]"></div>
                <div className="absolute -bottom-6 -right-6 text-white opacity-10 transform rotate-12">
                   <FileText size={100} />
                </div>

                {/* Header Controls (Status & Delete) */}
                <div className="relative z-10 flex justify-between items-start">
                   {/* Status Toggle */}
                   <div 
                      onClick={(e) => {
                         e.stopPropagation();
                         if (onToggleStatus) {
                            onToggleStatus(form.id, form.status === 'ACTIVE' ? 'CLOSED' : 'ACTIVE');
                         }
                      }}
                      className="flex items-center gap-2 bg-black/20 backdrop-blur-md rounded-full px-3 py-1 cursor-pointer hover:bg-black/30 transition-colors border border-white/10"
                      title={form.status === 'ACTIVE' ? "点击暂停收集" : "点击开始收集"}
                   >
                      <div className={`w-2 h-2 rounded-full ${form.status === 'ACTIVE' ? 'bg-green-400 animate-pulse' : 'bg-gray-400'}`}></div>
                      <span className="text-[10px] font-bold text-white">
                         {form.status === 'ACTIVE' ? '采集中' : '已停止'}
                      </span>
                   </div>

                   {/* Delete Button - Made clearer and reliable */}
                   <button 
                     onClick={(e) => handleDeleteClick(e, form.id)}
                     className="p-1.5 bg-white text-red-500 rounded-lg hover:bg-red-500 hover:text-white transition-all shadow-sm opacity-90 hover:opacity-100 cursor-pointer z-50"
                     title="删除此表单"
                   >
                      <Trash2 size={14} />
                   </button>
                </div>
             </div>

             {/* Card Content */}
             <div className="p-6 flex-1 flex flex-col">
                <div className="mb-4">
                  <h3 className="font-bold text-gray-900 text-lg line-clamp-1 mb-2 group-hover:text-indigo-600 transition-colors cursor-pointer" onClick={() => onSelectForm(form.id, 'ANALYTICS')} title={form.title}>
                    {form.title}
                  </h3>
                  <p className="text-xs text-gray-500 line-clamp-2 min-h-[2.5em] leading-relaxed">
                    {form.description || '暂无描述信息...'}
                  </p>
                </div>

                <div className="mt-auto pt-4 border-t border-gray-50 flex justify-between items-center text-xs">
                   <span className="flex items-center gap-1.5 text-gray-400">
                      <Clock size={14} /> {form.createdDate}
                   </span>
                   <span className={`flex items-center gap-1.5 font-bold px-2.5 py-1 rounded-full ${form.submissionCount > 0 ? 'bg-indigo-50 text-indigo-600' : 'bg-gray-50 text-gray-400'}`}>
                      <BarChart2 size={14} /> {form.submissionCount} 份数据
                   </span>
                </div>
             </div>

             {/* Action Footer */}
             <div className="grid grid-cols-3 divide-x divide-gray-100 border-t border-gray-100 bg-gray-50/50">
                <button 
                  onClick={() => onSelectForm(form.id, 'EDIT')}
                  className="py-3.5 flex items-center justify-center gap-2 text-xs font-bold text-gray-600 hover:bg-white hover:text-indigo-600 transition-all hover:shadow-inner"
                >
                   <Edit3 size={15} /> 设计
                </button>
                <button 
                  onClick={() => onSelectForm(form.id, 'ANALYTICS')}
                  className="py-3.5 flex items-center justify-center gap-2 text-xs font-bold text-gray-600 hover:bg-white hover:text-indigo-600 transition-all hover:shadow-inner"
                >
                   <BarChart2 size={15} /> 报表
                </button>
                <button 
                   onClick={() => onSelectForm(form.id, 'PREVIEW')}
                   className="py-3.5 flex items-center justify-center gap-2 text-xs font-bold text-gray-600 hover:bg-white hover:text-indigo-600 transition-all hover:shadow-inner"
                >
                   <Share2 size={15} /> 分享
                </button>
             </div>
          </div>
        ))}

        {forms.length === 0 && (
           <div className="col-span-full py-20 text-center text-gray-400 bg-white rounded-xl border border-dashed border-gray-200 cursor-pointer hover:bg-gray-50 transition-colors" onClick={onCreateForm}>
              <FileText size={48} className="mx-auto mb-4 opacity-20" />
              <p>暂无表单，点击此处新建</p>
           </div>
        )}
      </div>
    </div>
  );
};

